const getInitials = (name) => { const parts = name.split(' '); if (parts.length >= 2) return parts[0][0] + parts[1][0]; return name[0]; };
function PriorityBadge({ priority, size = 'normal', lang = 'pl' }) { if (!priority) return null; const p = PRIORITIES.find(pr => pr.id === priority); if (!p || !p.id) return null; const isSmall = size === 'small'; return <span className={`inline-flex items-center gap-1 ${isSmall ? 'px-1.5 py-0.5 text-xs' : 'px-2 py-1 text-xs'} rounded-full font-medium`} style={{ background: p.bg, color: p.color }}><Flag size={isSmall ? 10 : 12} />{lang === 'en' ? p.nameEn : p.name}</span>; }

// === NOTIFICATION SYSTEM (bez zmian) ===
const getReadTimestamps = (userId) => { try { return JSON.parse(localStorage.getItem(`av_read_${userId}`) || '{}'); } catch { return {}; } };
const setTaskRead = (taskId, userId) => { const ts = getReadTimestamps(userId); ts[taskId] = new Date().toISOString(); localStorage.setItem(`av_read_${userId}`, JSON.stringify(ts)); };
const setTaskUnread = (taskId, userId) => { const ts = getReadTimestamps(userId); delete ts[taskId]; localStorage.setItem(`av_read_${userId}`, JSON.stringify(ts)); };
const setAllTasksRead = (tasks, userId) => { const ts = getReadTimestamps(userId); const now = new Date().toISOString(); tasks.forEach(t => { ts[t.id] = now; }); localStorage.setItem(`av_read_${userId}`, JSON.stringify(ts)); };
const getUnreadComments = (task, userId, timestamps) => { if (!task.comments?.length) return []; const lastRead = timestamps[task.id]; if (!lastRead) return task.comments.filter(c => c.author !== userId); return task.comments.filter(c => c.author !== userId && new Date(c.createdAt) > new Date(lastRead)); };
const getUnreadCount = (task, userId, timestamps) => getUnreadComments(task, userId, timestamps).length;
const parseMentions = (text) => { const mentionRegex = /@(\w+)/g; const mentions = []; let match; while ((match = mentionRegex.exec(text)) !== null) { mentions.push(match[1].toLowerCase()); } return mentions; };
const getMentionsForUser = (task, userId, timestamps, teamMembers) => { const unreadComments = getUnreadComments(task, userId, timestamps); const userMember = teamMembers.find(m => m.id === userId); if (!userMember) return []; const userIdentifiers = [userId.toLowerCase(), userMember.name.split(' ')[0].toLowerCase(), userMember.name.toLowerCase().replace(/\s+/g, '_'), userMember.name.toLowerCase().replace(/\s+/g, '')]; return unreadComments.filter(c => { const mentions = parseMentions(c.text); return mentions.some(m => userIdentifiers.includes(m)); }); };
const getSeenTaskIds = (userId) => { try { return JSON.parse(localStorage.getItem(`av_seen_${userId}`) || '[]'); } catch { return []; } };
const markTaskAsSeen = (taskId, userId) => { const seen = getSeenTaskIds(userId); if (!seen.includes(taskId)) { seen.push(taskId); localStorage.setItem(`av_seen_${userId}`, JSON.stringify(seen)); } };
const getSoundEnabled = (userId) => { try { return localStorage.getItem(`av_sound_${userId}`) !== 'false'; } catch { return true; } };
const setSoundEnabled = (userId, enabled) => { localStorage.setItem(`av_sound_${userId}`, enabled ? 'true' : 'false'); };
const playNotificationSound = () => { try { const audio = new Audio(NOTIFICATION_SOUND); audio.volume = 0.3; audio.play().catch(() => {}); } catch (e) {} };

const getFileIcon = (type) => { if (type?.startsWith('image/')) return Image; if (type?.includes('spreadsheet') || type?.includes('excel')) return FileSpreadsheet; if (type?.includes('pdf') || type?.includes('document')) return FileText; return File; };
const formatFileSize = (bytes) => { if (bytes < 1024) return bytes + ' B'; if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB'; return (bytes / (1024 * 1024)).toFixed(1) + ' MB'; };
const generateId = () => Math.random().toString(36).substr(2, 9);
const formatDateTime = (date) => new Date(date).toLocaleString('pl-PL', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' });
const formatDateTimeEn = (date) => new Date(date).toLocaleString('en-US', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' });
const formatTimeAgo = (date) => { const diffMins = Math.floor((new Date() - new Date(date)) / 60000); if (diffMins < 1) return 'teraz'; if (diffMins < 60) return `${diffMins} min`; if (diffMins < 1440) return `${Math.floor(diffMins/60)} godz.`; return `${Math.floor(diffMins/1440)} dni`; };
const formatTimeAgoEn = (date) => { const diffMins = Math.floor((new Date() - new Date(date)) / 60000); if (diffMins < 1) return 'now'; if (diffMins < 60) return `${diffMins} min`; if (diffMins < 1440) return `${Math.floor(diffMins/60)}h`; return `${Math.floor(diffMins/1440)}d`; };

async function sendEmailNotification(to, assigneeName, taskTitle, assignedBy) { try { await fetch('/api/notify', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ to, assigneeName, taskTitle, assignedBy }) }); } catch (e) { console.log('Email skipped:', e); } }
async function sendCompletedEmail(task, completedByName) { if (!task.submitterEmail || !task.isExternal) return { sent: false }; try { const response = await fetch('/api/notify-completed', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ to: task.submitterEmail, requesterName: task.submittedBy, taskTitle: task.title, completedBy: completedByName, publicToken: task.publicToken }) }); const data = await response.json(); return { sent: data.success || false, messageId: data.messageId }; } catch (e) { return { sent: false, error: e.message }; } }

function sortTasks(tasks, sortBy) {
  const sorted = [...tasks];
  switch (sortBy) {
    case 'newest': return sorted.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
    case 'oldest': return sorted.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
    case 'priority': return sorted.sort((a, b) => { const orderA = PRIORITY_ORDER[a.priority] ?? 4; const orderB = PRIORITY_ORDER[b.priority] ?? 4; if (orderA !== orderB) return orderA - orderB; return new Date(b.createdAt) - new Date(a.createdAt); });
    case 'activity': return sorted.sort((a, b) => { const lastActivityA = a.comments?.length > 0 ? Math.max(...a.comments.map(c => new Date(c.createdAt).getTime())) : new Date(a.createdAt).getTime(); const lastActivityB = b.comments?.length > 0 ? Math.max(...b.comments.map(c => new Date(c.createdAt).getTime())) : new Date(b.createdAt).getTime(); return lastActivityB - lastActivityA; });
    case 'manual': return sorted.sort((a, b) => (a.order ?? 9999) - (b.order ?? 9999));
    default: return sorted;
  }
}

// === NOTIFICATION BELL (bez zmian) ===
function NotificationBell({ tasks, currentUser, readTimestamps, teamMembers, onSelectTask, t, lang }) {
  const [open, setOpen] = useState(false); const [soundEnabled, setSoundEnabledState] = useState(true); const ref = useRef(null); const buttonRef = useRef(null); const prevCountRef = useRef(0);
  useEffect(() => { setSoundEnabledState(getSoundEnabled(currentUser)); }, [currentUser]);
  useEffect(() => { const h = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); }; document.addEventListener('mousedown', h); return () => document.removeEventListener('mousedown', h); }, []);
  const notifications = useMemo(() => { const notifs = []; const cm = teamMembers.find(m => m.id === currentUser); const ui = cm ? [currentUser.toLowerCase(), cm.name.split(' ')[0].toLowerCase(), cm.name.toLowerCase().replace(/\s+/g, '_'), cm.name.toLowerCase().replace(/\s+/g, '')] : [currentUser.toLowerCase()]; tasks.forEach(task => { if (task.status === 'pending' || !task.comments?.length) return; const isA = task.assignees?.includes(currentUser); const isC = task.createdBy === currentUser; const isM = task.comments.some(c => parseMentions(c.text).some(m => ui.includes(m))); if (!isA && !isC && !isM) return; const uc = getUnreadComments(task, currentUser, readTimestamps); const uids = uc.map(c => c.id); const mns = getMentionsForUser(task, currentUser, readTimestamps, teamMembers); const mids = mns.map(m => m.id); task.comments.filter(c => c.author !== currentUser).forEach(comment => { const author = teamMembers.find(m => m.id === comment.author); const isUnread = uids.includes(comment.id); const isMention = mids.includes(comment.id) && isUnread; notifs.push({ id: `${isMention ? 'mention' : 'comment'}-${comment.id}`, type: isMention ? 'mention' : 'comment', task, comment, author, createdAt: comment.createdAt, isRead: !isUnread }); }); }); return notifs.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)); }, [tasks, currentUser, readTimestamps, teamMembers]);
  const unreadNotifications = notifications.filter(n => !n.isRead); const totalCount = unreadNotifications.length; const mentionCount = unreadNotifications.filter(n => n.type === 'mention').length;
  useEffect(() => { if (totalCount > prevCountRef.current && soundEnabled) playNotificationSound(); prevCountRef.current = totalCount; }, [totalCount, soundEnabled]);
  const toggleSound = () => { const nv = !soundEnabled; setSoundEnabledState(nv); setSoundEnabled(currentUser, nv); };
  const handleMarkAllRead = () => { setAllTasksRead(tasks, currentUser); window.location.reload(); };
  const ft = lang === 'en' ? formatTimeAgoEn : formatTimeAgo;
  const getPos = () => { if (!buttonRef.current) return {}; const r = buttonRef.current.getBoundingClientRect(); return { top: r.bottom + 8, right: Math.max(8, window.innerWidth - r.right) }; };
  return (<div className="relative" ref={ref}><button ref={buttonRef} onClick={() => setOpen(!open)} className="relative p-2 rounded-full hover:bg-gray-100" style={{ color: totalCount > 0 ? '#1a73e8' : '#5f6368' }}><Bell size={22} className={totalCount > 0 ? 'animate-pulse' : ''} />{totalCount > 0 && <span className="absolute -top-1 -right-1 min-w-[20px] h-5 flex items-center justify-center px-1 rounded-full text-xs font-bold text-white" style={{ background: mentionCount > 0 ? '#ea4335' : '#fbbc04' }}>{totalCount > 99 ? '99+' : totalCount}</span>}</button>{open && <div className="fixed w-96 max-w-[calc(100vw-2rem)] bg-white rounded-xl overflow-hidden" style={{ boxShadow: '0 4px 20px rgba(0,0,0,.15)', border: '1px solid #e8eaed', maxHeight: '80vh', zIndex: 9999, ...getPos() }}><div className="px-4 py-3 border-b flex items-center justify-between" style={{ borderColor: '#e8eaed', background: '#f8f9fa' }}><div className="flex items-center gap-2"><Bell size={18} style={{ color: '#1a73e8' }} /><h3 className="font-medium" style={{ color: '#202124' }}>{t.notifications}</h3>{totalCount > 0 && <span className="px-2 py-0.5 rounded-full text-xs font-medium" style={{ background: '#e8f0fe', color: '#1a73e8' }}>{totalCount}</span>}</div><div className="flex items-center gap-1"><button onClick={toggleSound} className="p-1.5 rounded-full hover:bg-gray-200" style={{ color: soundEnabled ? '#1a73e8' : '#9aa0a6' }}><Volume2 size={16} /></button>{totalCount > 0 && <button onClick={handleMarkAllRead} className="text-xs px-2 py-1 rounded hover:bg-gray-200" style={{ color: '#1a73e8' }}>{t.markAllRead}</button>}</div></div><div className="overflow-y-auto" style={{ maxHeight: '400px' }}>{notifications.length === 0 ? <div className="py-12 text-center"><Bell size={32} className="mx-auto mb-3" style={{ color: '#dadce0' }} /><p className="text-sm" style={{ color: '#9aa0a6' }}>{t.noNotifications}</p></div> : <div>{notifications.slice(0, 50).map(n => { const isMn = n.type === 'mention'; const mk = MARKETS.find(m => m.id === n.task.market); return <button key={n.id} onClick={() => { onSelectTask(n.task); setOpen(false); }} className="w-full px-4 py-3 flex gap-3 hover:bg-gray-50 text-left border-b" style={{ borderColor: '#f1f3f4', background: n.isRead ? '#fafafa' : 'white' }}><div className="relative flex-shrink-0"><div className="w-10 h-10 rounded-full flex items-center justify-center text-white text-sm font-medium" style={{ background: n.author?.color || '#5f6368', opacity: n.isRead ? 0.5 : 1 }}>{n.author ? getInitials(n.author.name) : '?'}</div>{isMn && !n.isRead && <div className="absolute -bottom-1 -right-1 w-5 h-5 rounded-full flex items-center justify-center" style={{ background: '#ea4335' }}><AtSign size={12} className="text-white" /></div>}</div><div className="flex-1 min-w-0"><div className="flex items-center gap-2 mb-0.5"><span className="font-medium text-sm" style={{ color: n.isRead ? '#9aa0a6' : '#202124' }}>{n.author?.name || '?'}</span><span className="text-xs" style={{ color: '#9aa0a6' }}>{ft(n.createdAt)}</span></div><p className="text-sm mb-1" style={{ color: n.isRead ? '#bdc1c6' : (isMn ? '#ea4335' : '#5f6368') }}>{isMn ? t.mentionedYou : t.newComment}</p><div className="flex items-center gap-1.5"><span style={{ opacity: n.isRead ? 0.5 : 1 }}>{mk?.icon}</span><span className="text-sm truncate" style={{ color: n.isRead ? '#9aa0a6' : '#202124' }}>{n.task.title}</span></div></div></button>; })}</div>}</div></div>}</div>);
}

// === MENTION INPUT (bez zmian) ===
function MentionInput({ value, onChange, onSubmit, placeholder, teamMembers }) {
  const [showS, setShowS] = useState(false); const [suggestions, setSuggestions] = useState([]); const [cp, setCp] = useState(0); const [ms, setMs] = useState(-1); const inputRef = useRef(null);
  const handleChange = (e) => { const nv = e.target.value; const c = e.target.selectionStart; onChange(nv); setCp(c); const tb = nv.substring(0, c); const la = tb.lastIndexOf('@'); if (la !== -1) { const ta = tb.substring(la + 1); const cb = la > 0 ? nv[la - 1] : ' '; if ((cb === ' ' || cb === '\n' || la === 0) && !ta.includes(' ')) { setMs(la); const q = ta.toLowerCase(); const f = teamMembers.filter(m => m.isActive !== false && (m.name.toLowerCase().includes(q) || m.id.toLowerCase().includes(q) || m.name.split(' ')[0].toLowerCase().includes(q))); setSuggestions(f.slice(0, 5)); setShowS(f.length > 0); return; } } setShowS(false); setMs(-1); };
  const insertM = (member) => { if (ms === -1) return; const b = value.substring(0, ms); const a = value.substring(cp); const mt = `@${member.id} `; onChange(b + mt + a); setShowS(false); setMs(-1); setTimeout(() => { if (inputRef.current) { inputRef.current.focus(); inputRef.current.setSelectionRange(ms + mt.length, ms + mt.length); } }, 0); };
  const handleKD = (e) => { if (e.key === 'Enter' && !e.shiftKey && !showS) { e.preventDefault(); onSubmit(); } if (e.key === 'Escape') setShowS(false); if (showS && suggestions.length > 0 && (e.key === 'Tab' || (e.key === 'Enter' && showS))) { e.preventDefault(); insertM(suggestions[0]); } };
  return <div className="relative flex-1"><input ref={inputRef} type="text" value={value} onChange={handleChange} onKeyDown={handleKD} placeholder={placeholder} className="w-full px-4 py-2.5 rounded-xl text-sm" style={{ background: '#f1f3f4', border: '1px solid #e8eaed' }} />{showS && <div className="absolute left-0 bottom-full mb-1 w-64 bg-white rounded-lg overflow-hidden z-50" style={{ boxShadow: '0 4px 12px rgba(0,0,0,.15)', border: '1px solid #e8eaed' }}><div className="px-3 py-2 border-b" style={{ borderColor: '#e8eaed', background: '#f8f9fa' }}><span className="text-xs font-medium" style={{ color: '#5f6368' }}>Oznacz osobę</span></div>{suggestions.map(m => <button key={m.id} onClick={() => insertM(m)} className="w-full px-3 py-2 flex items-center gap-2 hover:bg-gray-50 text-left"><div className="w-7 h-7 rounded-full flex items-center justify-center text-white text-xs font-medium" style={{ background: m.color }}>{getInitials(m.name)}</div><div><p className="text-sm font-medium" style={{ color: '#202124' }}>{m.name}</p><p className="text-xs" style={{ color: '#9aa0a6' }}>@{m.id}</p></div></button>)}</div>}</div>;
}

function CommentText({ text, teamMembers }) { const re = /(https?:\/\/[^\s]+|@\w+)/g; const ur = /(https?:\/\/[^\s]+)/g; const parts = text.split(re); return <span>{parts.map((p, i) => { if (p.match(ur)) { let l = p; try { l = new URL(p).hostname.replace('www.', ''); } catch {} return <a key={i} href={p} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-1 px-1 py-0.5 rounded hover:bg-blue-50" style={{ color: '#1a73e8', textDecoration: 'underline' }} onClick={e => e.stopPropagation()}><ExternalLink size={12} />{l}</a>; } if (p.startsWith('@')) { const n = p.substring(1).toLowerCase(); const m = teamMembers.find(m => m.id.toLowerCase() === n || m.name.split(' ')[0].toLowerCase() === n); return <span key={i} className="inline-flex items-center gap-0.5 px-1 py-0.5 rounded" style={{ background: '#e8f0fe', color: '#1a73e8', fontWeight: 500 }}><AtSign size={12} />{m ? m.name : p.substring(1)}</span>; } return p; })}</span>; }

function AttachmentUploader({ onUpload, uploading }) { const r = useRef(null); return <><input ref={r} type="file" multiple onChange={async (e) => { const f = Array.from(e.target.files); if (f.length > 0) await onUpload(f); e.target.value = ''; }} className="hidden" accept="image/*,.pdf,.doc,.docx,.xls,.xlsx,.csv,.txt,.ppt,.pptx" /><button type="button" onClick={() => r.current?.click()} disabled={uploading} className="p-2 rounded-full hover:bg-gray-100 disabled:opacity-50" style={{ color: '#5f6368' }}>{uploading ? <Loader2 size={18} className="animate-spin" /> : <Paperclip size={18} />}</button></>; }
function AttachmentList({ attachments, onRemove, showRemove = true }) { if (!attachments?.length) return null; return <div className="mt-2 space-y-1">{attachments.map(att => { const FI = getFileIcon(att.type); const isImg = att.type?.startsWith('image/'); return <div key={att.id} className="flex items-center gap-3 px-3 py-2 rounded-lg group" style={{ background: '#f1f3f4' }}>{isImg ? <img src={att.url} alt={att.name} className="w-10 h-10 rounded object-cover cursor-pointer" onClick={() => window.open(att.url, '_blank')} /> : <div className="w-10 h-10 rounded flex items-center justify-center" style={{ background: '#e8eaed' }}><FI size={20} style={{ color: '#5f6368' }} /></div>}<div className="flex-1 min-w-0"><p className="text-sm font-medium truncate" style={{ color: '#202124' }}>{att.name}</p><p className="text-xs" style={{ color: '#9aa0a6' }}>{formatFileSize(att.size)}</p></div><a href={att.url} target="_blank" rel="noopener noreferrer" className="p-1.5 rounded hover:bg-gray-200" style={{ color: '#5f6368' }}><Download size={16} /></a>{showRemove && onRemove && <button onClick={() => onRemove(att.id)} className="p-1.5 rounded hover:bg-red-50 opacity-0 group-hover:opacity-100" style={{ color: '#ea4335' }}><X size={16} /></button>}</div>; })}</div>; }

// === LOGIN (bez zmian) ===
function LoginScreen({ onLogin, teamMembers }) { const [su, setSu] = useState(''); const [pin, setPin] = useState(''); const [err, setErr] = useState(''); const [ld, setLd] = useState(false); const am = teamMembers.filter(m => m.isActive !== false); const hl = async (e) => { e.preventDefault(); if (!su) { setErr('Wybierz osobę'); return; } if (!pin || pin.length < 4) { setErr('Wpisz 4-cyfrowy PIN'); return; } setLd(true); setErr(''); try { const r = await fetch('/api/auth/login', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ userId: su, pin }) }); const d = await r.json(); if (d.success) { localStorage.setItem('av_tasks_user', su); onLogin(su); } else { setErr('Nieprawidłowy PIN'); setPin(''); } } catch { setErr('Błąd połączenia'); } setLd(false); }; return <div className="min-h-screen flex items-center justify-center p-4" style={{ background: '#f8f9fa' }}><div className="bg-white rounded-2xl p-8 w-full max-w-sm" style={{ boxShadow: '0 1px 3px 0 rgba(60,64,67,.3), 0 4px 8px 3px rgba(60,64,67,.15)' }}><div className="text-center mb-8"><img src="https://angloville.com/wp-content/themes/angloville/assets/images/logo.svg" alt="Angloville" className="h-10 mx-auto mb-4" /><h1 className="text-xl font-semibold" style={{ color: '#202124' }}>Marketing Tasks</h1></div><form onSubmit={hl} className="space-y-4">{err && <div className="p-3 rounded-lg text-sm text-center" style={{ background: '#fce8e6', color: '#c5221f' }}>{err}</div>}<div><label className="block text-sm font-medium mb-1.5" style={{ color: '#202124' }}>Osoba</label><select value={su} onChange={e => { setSu(e.target.value); setErr(''); }} className="w-full px-4 py-3 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }}><option value="">Wybierz...</option>{am.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}</select></div><div><label className="block text-sm font-medium mb-1.5" style={{ color: '#202124' }}>PIN</label><input type="password" value={pin} onChange={e => { setPin(e.target.value.replace(/\D/g, '').slice(0, 4)); setErr(''); }} className="w-full px-4 py-3 border rounded-lg text-sm text-center tracking-widest" style={{ borderColor: '#dadce0' }} placeholder="••••" maxLength={4} inputMode="numeric" /></div><button type="submit" disabled={ld} className="w-full py-3 rounded-lg font-medium flex items-center justify-center gap-2 disabled:opacity-70" style={{ background: '#1a73e8', color: 'white' }}>{ld ? <Loader2 size={18} className="animate-spin" /> : <Lock size={18} />}{ld ? 'Logowanie...' : 'Zaloguj się'}</button></form></div></div>; }

// === RICH TEXT (bez zmian) ===
function RichTextEditor({ value, onChange, placeholder, minHeight = '150px' }) { const er = useRef(null); useEffect(() => { if (er.current && er.current.innerHTML !== value) er.current.innerHTML = value || ''; }, [value]); const ec = (cmd, v = null) => { document.execCommand(cmd, false, v); er.current?.focus(); hc(); }; const hc = () => { if (er.current) onChange(er.current.innerHTML); }; return <div className="border rounded-lg overflow-hidden bg-white" style={{ borderColor: '#dadce0' }}><div className="flex items-center gap-0.5 px-2 py-1.5 border-b flex-wrap" style={{ background: '#f1f3f4', borderColor: '#dadce0' }}><button type="button" onClick={() => ec('undo')} className="p-1.5 rounded hover:bg-gray-200"><Undo size={18} style={{ color: '#444746' }} /></button><button type="button" onClick={() => ec('redo')} className="p-1.5 rounded hover:bg-gray-200"><Redo size={18} style={{ color: '#444746' }} /></button><div className="w-px h-5 mx-1.5" style={{ background: '#dadce0' }} /><button type="button" onClick={() => ec('bold')} className="p-1.5 rounded hover:bg-gray-200"><Bold size={18} style={{ color: '#444746' }} /></button><button type="button" onClick={() => ec('italic')} className="p-1.5 rounded hover:bg-gray-200"><Italic size={18} style={{ color: '#444746' }} /></button><button type="button" onClick={() => ec('underline')} className="p-1.5 rounded hover:bg-gray-200"><Underline size={18} style={{ color: '#444746' }} /></button><div className="w-px h-5 mx-1.5" style={{ background: '#dadce0' }} /><button type="button" onClick={() => { const u = prompt('URL:'); if (u) ec('createLink', u); }} className="p-1.5 rounded hover:bg-gray-200"><Link2 size={18} style={{ color: '#444746' }} /></button><div className="w-px h-5 mx-1.5" style={{ background: '#dadce0' }} /><button type="button" onClick={() => ec('insertUnorderedList')} className="p-1.5 rounded hover:bg-gray-200"><List size={18} style={{ color: '#444746' }} /></button><button type="button" onClick={() => ec('insertOrderedList')} className="p-1.5 rounded hover:bg-gray-200"><ListOrdered size={18} style={{ color: '#444746' }} /></button></div><div ref={er} contentEditable onInput={hc} onBlur={hc} className="px-4 py-3 text-sm focus:outline-none overflow-y-auto" style={{ color: '#202124', minHeight, maxHeight: '400px' }} data-placeholder={placeholder} suppressContentEditableWarning /></div>; }
function RichTextDisplay({ html }) { if (!html) return null; return <div className="text-sm leading-relaxed prose prose-sm max-w-none" style={{ color: '#3c4043' }} dangerouslySetInnerHTML={{ __html: html }} />; }
function ClickableLinks({ text }) { if (!text) return null; const ur = /(https?:\/\/[^\s]+)/gi; return <div className="space-y-1">{text.split('\n').map((line, i) => <div key={i} className="text-sm">{line.split(ur).map((p, j) => p.match(ur) ? <a key={j} href={p} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-1 px-2 py-1 rounded-full hover:bg-blue-50" style={{ color: '#1a73e8' }}><ExternalLink size={12} />{(() => { try { return new URL(p).hostname.replace('www.', ''); } catch { return p; } })()}</a> : <span key={j} style={{ color: '#5f6368' }}>{p}</span>)}</div>)}</div>; }
function TranslateButton({ task, size = 'normal' }) { const [sp, setSp] = useState(false); if (task.language !== 'en') return null; return <><button onClick={e => { e.stopPropagation(); setSp(true); }} className="p-1 rounded hover:bg-blue-50" style={{ color: '#1a73e8' }}><Languages size={size === 'small' ? 14 : 16} /></button>{sp && <TranslationPopup title={task.title} description={task.description} onClose={() => setSp(false)} />}</>; }
function TranslationPopup({ title, description, onClose }) { const [tt, setTt] = useState(''); const [td, setTd] = useState(''); const [ld, setLd] = useState(true); useEffect(() => { (async () => { setLd(true); const pt = title?.replace(/<[^>]*>/g, ' ').trim() || ''; const pd = description?.replace(/<[^>]*>/g, ' ').trim() || ''; try { const [a, b] = await Promise.all([fetch(`https://api.mymemory.translated.net/get?q=${encodeURIComponent(pt)}&langpair=en|pl`).then(r => r.json()), pd ? fetch(`https://api.mymemory.translated.net/get?q=${encodeURIComponent(pd.substring(0, 500))}&langpair=en|pl`).then(r => r.json()) : null]); setTt(a?.responseData?.translatedText || pt); setTd(b?.responseData?.translatedText || pd); } catch { setTt(pt); setTd(pd); } setLd(false); })(); }, [title, description]); return <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4" onClick={onClose}><div className="bg-white rounded-xl w-full max-w-md" style={{ boxShadow: '0 24px 38px 3px rgba(0,0,0,.14)' }} onClick={e => e.stopPropagation()}><div className="p-4 border-b flex items-center justify-between" style={{ borderColor: '#e8eaed' }}><div className="flex items-center gap-2"><Languages size={20} style={{ color: '#1a73e8' }} /><h3 className="font-medium" style={{ color: '#202124' }}>🇬🇧 → 🇵🇱</h3></div><button onClick={onClose} className="p-1 rounded hover:bg-gray-100" style={{ color: '#5f6368' }}><X size={18} /></button></div><div className="p-5 space-y-4">{ld ? <div className="flex items-center justify-center py-8"><Loader2 size={24} className="animate-spin" style={{ color: '#1a73e8' }} /></div> : <><div><label className="block text-xs font-medium mb-1" style={{ color: '#5f6368' }}>Tytuł</label><div className="p-3 rounded-lg" style={{ background: '#e8f0fe' }}><p className="text-sm font-medium" style={{ color: '#202124' }}>{tt}</p></div></div>{td && <div><label className="block text-xs font-medium mb-1" style={{ color: '#5f6368' }}>Opis</label><div className="p-3 rounded-lg" style={{ background: '#e8f0fe' }}><p className="text-sm" style={{ color: '#3c4043' }}>{td}</p></div></div>}</>}</div></div></div>; }
function SubtaskProgress({ subtasks }) { if (!subtasks?.length) return null; const d = subtasks.filter(s => s.status === 'closed').length; return <div className="flex items-center gap-1.5"><ListTodo size={12} style={{ color: '#5f6368' }} /><span className="text-xs" style={{ color: '#5f6368' }}>{d}/{subtasks.length}</span></div>; }

// === DASHBOARD (bez zmian) ===
function DashboardPanel({ tasks, teamMembers, onClose, t, lang }) {
  const [period, setPeriod] = useState(7); const now = new Date(); const sd = new Date(now.getTime() - period * 24 * 60 * 60 * 1000); const am = teamMembers.filter(m => m.isActive !== false && !m.isManager);
  const stats = useMemo(() => { const ci = tasks.filter(t => new Date(t.createdAt) >= sd); const cl = tasks.filter(t => t.status === 'closed' && t.updatedAt && new Date(t.updatedAt) >= sd); const pp = {}; am.forEach(m => { pp[m.id] = { name: m.name, color: m.color, created: 0, closed: 0, open: 0, subtasksDone: 0, comments: 0 }; }); ci.forEach(t => { if (t.createdBy && pp[t.createdBy]) pp[t.createdBy].created++; }); cl.forEach(t => { (t.assignees || []).forEach(a => { if (pp[a]) pp[a].closed++; }); }); tasks.filter(t => t.status === 'open' || t.status === 'longterm').forEach(t => { (t.assignees || []).forEach(a => { if (pp[a]) pp[a].open++; }); }); tasks.forEach(t => { (t.comments || []).forEach(c => { if (new Date(c.createdAt) >= sd && pp[c.author]) pp[c.author].comments++; }); }); tasks.forEach(t => { (t.subtasks || []).forEach(s => { if (s.status === 'closed' && s.assignee && pp[s.assignee]) pp[s.assignee].subtasksDone++; }); }); const dd = []; for (let i = period - 1; i >= 0; i--) { const d = new Date(now.getTime() - i * 24 * 60 * 60 * 1000); const ds = d.toISOString().split('T')[0]; dd.push({ date: d.toLocaleDateString(lang === 'en' ? 'en-US' : 'pl-PL', { day: 'numeric', month: 'short' }), created: tasks.filter(t => t.createdAt?.startsWith(ds)).length, closed: tasks.filter(t => t.status === 'closed' && t.updatedAt?.startsWith(ds)).length }); } return { totalCreated: ci.length, totalClosed: cl.length, currentOpen: tasks.filter(t => t.status === 'open' || t.status === 'longterm').length, currentPending: tasks.filter(t => t.status === 'pending').length, perPerson: pp, dailyData: dd, createdPerDay: (ci.length / period).toFixed(1), closedPerDay: (cl.length / period).toFixed(1) }; }, [tasks, teamMembers, period, sd]);
  return <aside className="w-full lg:w-[640px] bg-white border-l flex flex-col overflow-hidden flex-shrink-0 fixed lg:static inset-0 z-40 lg:z-auto" style={{ borderColor: '#e8eaed' }}><div className="p-4 border-b flex items-center justify-between" style={{ borderColor: '#e8eaed' }}><div className="flex items-center gap-2"><BarChart3 size={20} style={{ color: '#1a73e8' }} /><h2 className="font-medium" style={{ color: '#202124' }}>{t.dashboardTitle}</h2></div><div className="flex items-center gap-2"><select value={period} onChange={e => setPeriod(Number(e.target.value))} className="text-sm px-3 py-1.5 border rounded-lg" style={{ borderColor: '#dadce0' }}><option value={7}>{t.last7days}</option><option value={14}>{t.last14days}</option><option value={30}>{t.last30days}</option></select><button onClick={onClose} className="p-2 rounded-full hover:bg-gray-100" style={{ color: '#5f6368' }}><X size={18} /></button></div></div><div className="flex-1 overflow-y-auto p-5 space-y-6"><div className="grid grid-cols-2 gap-3"><div className="p-4 rounded-xl" style={{ background: '#e8f0fe' }}><div className="flex items-center gap-2 mb-1"><TrendingUp size={16} style={{ color: '#1a73e8' }} /><span className="text-xs font-medium" style={{ color: '#1a73e8' }}>{t.tasksCreated}</span></div><div className="text-3xl font-bold" style={{ color: '#1a73e8' }}>{stats.totalCreated}</div><div className="text-xs mt-1" style={{ color: '#5f6368' }}>{stats.createdPerDay}{t.perDay}</div></div><div className="p-4 rounded-xl" style={{ background: '#e6f4ea' }}><div className="flex items-center gap-2 mb-1"><CheckCircle size={16} style={{ color: '#34a853' }} /><span className="text-xs font-medium" style={{ color: '#34a853' }}>{t.tasksClosed}</span></div><div className="text-3xl font-bold" style={{ color: '#34a853' }}>{stats.totalClosed}</div><div className="text-xs mt-1" style={{ color: '#5f6368' }}>{stats.closedPerDay}{t.perDay}</div></div><div className="p-4 rounded-xl" style={{ background: '#fff3e0' }}><div className="flex items-center gap-2 mb-1"><Circle size={16} style={{ color: '#ff7043' }} /><span className="text-xs font-medium" style={{ color: '#ff7043' }}>{t.tasksOpen}</span></div><div className="text-3xl font-bold" style={{ color: '#ff7043' }}>{stats.currentOpen}</div></div><div className="p-4 rounded-xl" style={{ background: '#fef7e0' }}><div className="flex items-center gap-2 mb-1"><AlertCircle size={16} style={{ color: '#fbbc04' }} /><span className="text-xs font-medium" style={{ color: '#fbbc04' }}>{t.pending}</span></div><div className="text-3xl font-bold" style={{ color: '#fbbc04' }}>{stats.currentPending}</div></div></div><div><h3 className="text-sm font-medium mb-3" style={{ color: '#202124' }}>Dzienne zadania</h3><div className="rounded-xl border p-4" style={{ borderColor: '#e8eaed' }}><div className="flex items-end gap-1" style={{ height: '120px' }}>{stats.dailyData.map((d, i) => { const mv = Math.max(...stats.dailyData.map(x => Math.max(x.created, x.closed)), 1); return <div key={i} className="flex-1 flex flex-col items-center gap-0.5" title={`${d.date}: ${d.created}/${d.closed}`}><div className="w-full flex gap-0.5 items-end" style={{ height: '100px' }}><div className="flex-1 rounded-t" style={{ height: `${Math.max((d.created/mv)*100,2)}%`, background: '#4285f4', minHeight: d.created > 0 ? '4px' : '0' }} /><div className="flex-1 rounded-t" style={{ height: `${Math.max((d.closed/mv)*100,2)}%`, background: '#34a853', minHeight: d.closed > 0 ? '4px' : '0' }} /></div>{(i % Math.ceil(stats.dailyData.length/7) === 0 || i === stats.dailyData.length-1) && <span style={{ color: '#9aa0a6', fontSize: '9px' }}>{d.date}</span>}</div>; })}</div><div className="flex items-center gap-4 mt-3 pt-3 border-t" style={{ borderColor: '#e8eaed' }}><div className="flex items-center gap-1.5"><div className="w-3 h-3 rounded" style={{ background: '#4285f4' }} /><span className="text-xs" style={{ color: '#5f6368' }}>{t.tasksCreated}</span></div><div className="flex items-center gap-1.5"><div className="w-3 h-3 rounded" style={{ background: '#34a853' }} /><span className="text-xs" style={{ color: '#5f6368' }}>{t.tasksClosed}</span></div></div></div></div><div><h3 className="text-sm font-medium mb-3" style={{ color: '#202124' }}>Obciążenie na osobę</h3><div className="space-y-3">{Object.entries(stats.perPerson).map(([id, p]) => <div key={id} className="rounded-xl border p-4" style={{ borderColor: '#e8eaed' }}><div className="flex items-center gap-3 mb-3"><div className="w-8 h-8 rounded-full flex items-center justify-center text-white text-xs font-medium" style={{ background: p.color }}>{getInitials(p.name)}</div><span className="flex-1 text-sm font-medium" style={{ color: '#202124' }}>{p.name}</span><div className="text-right"><span className="text-lg font-bold" style={{ color: '#202124' }}>{p.open}</span><span className="text-xs ml-1" style={{ color: '#5f6368' }}>otwarte</span></div></div><div className="grid grid-cols-4 gap-2 text-center">{[{v:p.created,c:'#4285f4',l:'utworz.'},{v:p.closed,c:'#34a853',l:'zamkn.'},{v:p.subtasksDone,c:'#a142f4',l:'subtaski'},{v:p.comments,c:'#ff7043',l:'koment.'}].map((x,i) => <div key={i} className="p-2 rounded-lg" style={{ background: '#f1f3f4' }}><div className="text-sm font-bold" style={{ color: x.c }}>{x.v}</div><div className="text-xs" style={{ color: '#5f6368' }}>{x.l}</div></div>)}</div></div>)}</div></div></div></aside>;
}

// === USERS PANEL (bez zmian) ===
function UsersPanel({ teamMembers, onUpdate, onClose, t }) {
  const [au, setAu] = useState([]); const [ld, setLd] = useState(true); const [eu, setEu] = useState(null); const [sa, setSa] = useState(false);
  useEffect(() => { la(); }, []); const la = async () => { setLd(true); setAu(await getAllTeamMembers()); setLd(false); }; const hs = async (d) => { if (eu) await updateTeamMember(eu.id, d); else await createTeamMember(d); await la(); onUpdate(); setEu(null); setSa(false); }; const ht = async (u) => { await updateTeamMember(u.id, { isActive: !u.isActive }); await la(); onUpdate(); };
  return <aside className="w-full lg:w-[500px] bg-white border-l flex flex-col overflow-hidden flex-shrink-0 fixed lg:static inset-0 z-40 lg:z-auto" style={{ borderColor: '#e8eaed' }}><div className="p-4 border-b flex items-center justify-between" style={{ borderColor: '#e8eaed' }}><div className="flex items-center gap-2"><Users size={20} style={{ color: '#1a73e8' }} /><h2 className="font-medium" style={{ color: '#202124' }}>{t.usersPanel}</h2></div><div className="flex items-center gap-2"><button onClick={() => { setSa(true); setEu(null); }} className="flex items-center gap-1 px-3 py-1.5 rounded-lg text-sm font-medium" style={{ background: '#1a73e8', color: 'white' }}><UserPlus size={16} /> {t.addUser}</button><button onClick={onClose} className="p-2 rounded-full hover:bg-gray-100" style={{ color: '#5f6368' }}><X size={18} /></button></div></div><div className="flex-1 overflow-y-auto p-4">{ld ? <div className="flex items-center justify-center py-8"><Loader2 size={24} className="animate-spin" style={{ color: '#1a73e8' }} /></div> : (sa || eu) ? <UserForm user={eu} onSave={hs} onCancel={() => { setSa(false); setEu(null); }} t={t} /> : <div className="space-y-2">{au.map(u => <div key={u.id} className="p-4 rounded-lg border" style={{ borderColor: '#e8eaed', opacity: u.isActive ? 1 : 0.7 }}><div className="flex items-start gap-3"><div className="w-10 h-10 rounded-full flex items-center justify-center text-white text-sm font-medium" style={{ background: u.color }}>{getInitials(u.name)}</div><div className="flex-1 min-w-0"><div className="flex items-center gap-2"><h3 className="font-medium" style={{ color: '#202124' }}>{u.name}</h3>{u.isManager && <span className="text-xs px-2 py-0.5 rounded-full" style={{ background: '#e8f0fe', color: '#1a73e8' }}>Admin</span>}{!u.isActive && <span className="text-xs px-2 py-0.5 rounded-full" style={{ background: '#fce8e6', color: '#c5221f' }}>Nieaktywny</span>}</div><p className="text-sm" style={{ color: '#5f6368' }}>{u.email}</p></div><div className="flex items-center gap-1"><button onClick={() => setEu(u)} className="p-2 rounded-full hover:bg-gray-100" style={{ color: '#5f6368' }}><Edit3 size={16} /></button><button onClick={() => ht(u)} className="p-2 rounded-full hover:bg-gray-100" style={{ color: u.isActive ? '#ea4335' : '#34a853' }}>{u.isActive ? <X size={16} /> : <Check size={16} />}</button></div></div></div>)}</div>}</div></aside>;
}
function UserForm({ user, onSave, onCancel, t }) { const ie = !!user?.id; const [f, sF] = useState({ id: user?.id || '', name: user?.name || '', email: user?.email || '', pin: '', color: user?.color || COLORS[Math.floor(Math.random()*COLORS.length)], role: user?.role || '', isManager: user?.isManager || false, language: user?.language || 'pl', restrictedToMarket: user?.restrictedToMarket || null, seeOnlyAssigned: user?.seeOnlyAssigned || false }); const hs = (e) => { e.preventDefault(); const id = f.id || f.name.toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, ''); const d = { ...f, id }; if (ie && !f.pin) delete d.pin; onSave(d); }; return <form onSubmit={hs} className="space-y-4"><div><label className="block text-sm font-medium mb-1" style={{ color: '#202124' }}>{t.name} *</label><input type="text" value={f.name} onChange={e => sF({...f, name: e.target.value})} className="w-full px-3 py-2 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }} required /></div><div><label className="block text-sm font-medium mb-1" style={{ color: '#202124' }}>{t.email} *</label><input type="email" value={f.email} onChange={e => sF({...f, email: e.target.value})} className="w-full px-3 py-2 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }} required /></div><div className="grid grid-cols-2 gap-4"><div><label className="block text-sm font-medium mb-1" style={{ color: '#202124' }}>PIN</label><input type="text" value={f.pin} onChange={e => sF({...f, pin: e.target.value.replace(/\D/g,'').slice(0,4)})} className="w-full px-3 py-2 border rounded-lg text-sm text-center tracking-widest" style={{ borderColor: '#dadce0' }} maxLength={4} placeholder={ie ? '••••' : ''} required={!ie} /></div><div><label className="block text-sm font-medium mb-1" style={{ color: '#202124' }}>{t.color}</label><div className="flex gap-1 flex-wrap">{COLORS.map(c => <button key={c} type="button" onClick={() => sF({...f,color:c})} className="w-6 h-6 rounded-full" style={{ background: c, border: f.color === c ? '2px solid #202124' : '2px solid transparent' }} />)}</div></div></div><div><label className="block text-sm font-medium mb-1" style={{ color: '#202124' }}>{t.role}</label><input type="text" value={f.role} onChange={e => sF({...f, role: e.target.value})} className="w-full px-3 py-2 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }} /></div><div className="grid grid-cols-2 gap-4"><div><label className="block text-sm font-medium mb-1" style={{ color: '#202124' }}>{t.language}</label><select value={f.language} onChange={e => sF({...f, language: e.target.value})} className="w-full px-3 py-2 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }}><option value="pl">🇵🇱 {t.polish}</option><option value="en">🇬🇧 {t.english}</option></select></div><div><label className="block text-sm font-medium mb-1" style={{ color: '#202124' }}>{t.restrictedMarket}</label><select value={f.restrictedToMarket || ''} onChange={e => sF({...f, restrictedToMarket: e.target.value || null})} className="w-full px-3 py-2 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }}><option value="">{t.allMarketsAccess}</option>{MARKETS.map(m => <option key={m.id} value={m.id}>{m.icon} {m.name}</option>)}</select></div></div><div className="space-y-3"><label className="flex items-center gap-3 cursor-pointer"><input type="checkbox" checked={f.seeOnlyAssigned} onChange={e => sF({...f, seeOnlyAssigned: e.target.checked})} className="w-4 h-4 rounded" /><span className="text-sm">{t.seeOnlyAssigned}</span></label><label className="flex items-center gap-3 cursor-pointer"><input type="checkbox" checked={f.isManager} onChange={e => sF({...f, isManager: e.target.checked})} className="w-4 h-4 rounded" /><span className="text-sm">{t.isManager}</span></label></div><div className="flex gap-3 pt-4"><button type="submit" className="flex-1 py-2.5 rounded-lg font-medium text-sm" style={{ background: '#1a73e8', color: 'white' }}>{t.save}</button><button type="button" onClick={onCancel} className="flex-1 py-2.5 rounded-lg font-medium text-sm" style={{ background: '#f1f3f4', color: '#5f6368' }}>{t.cancel}</button></div></form>; }

// === QUICK LINKS (bez zmian) ===
function QuickLinksSection({ currentUser, t }) { const [lk, setLk] = useState([]); const [ld, setLd] = useState(true); const [sa, setSa] = useState(false); const [nl, setNl] = useState({ name: '', url: '' }); const [ex, setEx] = useState(true); useEffect(() => { ll(); }, [currentUser]); const ll = async () => { setLd(true); setLk(await getQuickLinks(currentUser)); setLd(false); }; const ha = async () => { if (!nl.name.trim() || !nl.url.trim()) return; await createQuickLink({ ...nl, userId: currentUser }); setNl({ name: '', url: '' }); setSa(false); ll(); }; const hd = async (id) => { await deleteQuickLink(id); ll(); }; return <div className="mt-4 mx-2"><button onClick={() => setEx(!ex)} className="w-full flex items-center justify-between px-2 py-1 text-xs font-medium rounded hover:bg-gray-100" style={{ color: '#5f6368' }}><span>{t.myLinks}</span><ChevronDown size={14} className={`transition-transform ${ex ? '' : '-rotate-90'}`} /></button>{ex && <div className="mt-2 space-y-1">{ld ? <Loader2 size={14} className="animate-spin mx-auto" style={{ color: '#5f6368' }} /> : <>{lk.map(l => <div key={l.id} className="flex items-center gap-1 group"><a href={l.url} target="_blank" rel="noopener noreferrer" className="flex-1 text-xs px-2 py-1.5 rounded hover:bg-gray-100 truncate" style={{ color: '#1a73e8' }}>{l.name}</a><button onClick={() => hd(l.id)} className="opacity-0 group-hover:opacity-100 p-1 rounded hover:bg-red-50" style={{ color: '#ea4335' }}><X size={12} /></button></div>)}{lk.length === 0 && !sa && <p className="text-xs px-2" style={{ color: '#9aa0a6' }}>{t.noLinks}</p>}{sa ? <div className="p-2 rounded-lg" style={{ background: '#f1f3f4' }}><input type="text" value={nl.name} onChange={e => setNl({...nl, name: e.target.value})} className="w-full px-2 py-1 text-xs rounded border mb-1" style={{ borderColor: '#dadce0' }} placeholder="Nazwa" /><input type="url" value={nl.url} onChange={e => setNl({...nl, url: e.target.value})} className="w-full px-2 py-1 text-xs rounded border mb-2" style={{ borderColor: '#dadce0' }} placeholder="https://..." /><div className="flex gap-1"><button onClick={ha} className="flex-1 py-1 rounded text-xs font-medium" style={{ background: '#1a73e8', color: 'white' }}>{t.add}</button><button onClick={() => { setSa(false); setNl({name:'',url:''}); }} className="px-2 py-1 rounded text-xs" style={{ color: '#5f6368' }}>{t.cancel}</button></div></div> : <button onClick={() => setSa(true)} className="w-full text-xs px-2 py-1.5 rounded hover:bg-gray-100 text-left" style={{ color: '#1a73e8' }}>+ {t.addLink}</button>}</>}</div>}</div>; }

// === SORT DROPDOWN (bez zmian) ===
function SortDropdown({ value, onChange, t }) { const [op, setOp] = useState(false); const r = useRef(null); useEffect(() => { const h = e => { if (r.current && !r.current.contains(e.target)) setOp(false); }; document.addEventListener('mousedown', h); return () => document.removeEventListener('mousedown', h); }, []); const opts = [{ id: 'manual', label: 'Ręcznie ↕', icon: GripVertical }, { id: 'newest', label: t.sortNewest, icon: ArrowDown }, { id: 'oldest', label: t.sortOldest, icon: ArrowUp }, { id: 'priority', label: t.sortPriority, icon: Flag }, { id: 'activity', label: t.sortActivity, icon: Activity }]; const cur = opts.find(o => o.id === value) || opts[0]; return <div className="relative" ref={r}><button onClick={() => setOp(!op)} className="flex items-center gap-2 px-3 py-2 rounded-lg text-sm hover:bg-gray-100" style={{ color: '#5f6368', border: '1px solid #dadce0' }}><ArrowUpDown size={16} /><span className="hidden sm:inline">{cur.label}</span><ChevronDown size={14} className={`transition-transform ${op ? 'rotate-180' : ''}`} /></button>{op && <div className="absolute right-0 top-full mt-1 bg-white rounded-lg py-1 z-20 min-w-[180px]" style={{ boxShadow: '0 4px 12px rgba(0,0,0,.15)', border: '1px solid #e8eaed' }}>{opts.map(o => { const I = o.icon; return <button key={o.id} onClick={() => { onChange(o.id); setOp(false); }} className="w-full flex items-center gap-3 px-4 py-2.5 text-sm hover:bg-gray-50 text-left" style={{ color: value === o.id ? '#1a73e8' : '#202124', background: value === o.id ? '#e8f0fe' : 'transparent' }}><I size={16} /><span>{o.label}</span>{value === o.id && <Check size={16} className="ml-auto" />}</button>; })}</div>}</div>; }

// === PENDING VIEW (bez zmian) ===
function PendingView({ tasks, approveTask, deleteTask, currentUser, t, lang, teamMembers }) { const [sel, setSel] = useState({}); const tog = (tid, mid) => { setSel(p => { const c = p[tid] || []; return { ...p, [tid]: c.includes(mid) ? c.filter(x => x !== mid) : [...c, mid] }; }); }; if (!tasks.length) return <div className="max-w-3xl mx-auto text-center py-16"><CheckCircle size={48} className="mx-auto mb-4" style={{ color: '#34a853', opacity: 0.4 }} /><p style={{ color: '#5f6368' }}>{t.noPending}</p></div>; return <div className="max-w-3xl mx-auto space-y-4">{tasks.map(task => { const mk = MARKETS.find(m => m.id === task.market); const as = sel[task.id] || task.assignees || []; return <div key={task.id} className="bg-white rounded-xl p-5 border" style={{ borderColor: '#e8eaed' }}>{task.isExternal && <div className="flex items-center gap-2 mb-3 pb-3 border-b flex-wrap" style={{ borderColor: '#e8eaed' }}><ExternalLink size={14} style={{ color: '#fbbc04' }} /><span className="text-xs font-medium" style={{ color: '#b06000' }}>{t.external}</span>{task.language === 'en' && <span className="text-xs px-1.5 py-0.5 rounded" style={{ background: '#e8f0fe', color: '#1a73e8' }}>🇬🇧</span>}<span className="text-xs" style={{ color: '#9aa0a6' }}>{t.from} {task.submittedBy}</span></div>}<div className="flex items-start gap-3 mb-4"><span className="text-xl">{mk?.icon}</span><div className="flex-1"><div className="flex items-center gap-2 flex-wrap"><h3 className="font-medium text-lg" style={{ color: '#202124' }}>{task.title}</h3><TranslateButton task={task} /><PriorityBadge priority={task.priority} lang={lang} /></div>{task.description && <div className="mt-2"><RichTextDisplay html={task.description} /></div>}{task.links && <div className="mt-3 p-3 rounded-lg" style={{ background: '#f8f9fa' }}><ClickableLinks text={task.links} /></div>}<AttachmentList attachments={task.attachments} showRemove={false} /></div></div><div className="mb-4"><p className="text-xs font-medium mb-2" style={{ color: '#5f6368' }}>{t.assignTo}</p><div className="flex flex-wrap gap-2">{teamMembers.filter(m => m.isActive !== false).map(m => <button key={m.id} onClick={() => tog(task.id, m.id)} className="flex items-center gap-2 px-3 py-2 rounded-full border text-sm" style={{ borderColor: as.includes(m.id) ? '#1a73e8' : '#dadce0', background: as.includes(m.id) ? '#e8f0fe' : 'white', color: as.includes(m.id) ? '#1a73e8' : '#202124' }}><div className="w-5 h-5 rounded-full flex items-center justify-center text-white text-xs font-medium" style={{ background: m.color }}>{getInitials(m.name)}</div><span>{m.name.split(' ')[0]}</span>{as.includes(m.id) && <Check size={14} />}</button>)}</div></div><div className="flex gap-2 pt-4 border-t" style={{ borderColor: '#e8eaed' }}><button onClick={() => approveTask(task, as)} disabled={!as.length} className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg font-medium disabled:opacity-50" style={{ background: as.length ? '#1a73e8' : '#f1f3f4', color: as.length ? 'white' : '#9aa0a6' }}><Check size={18} /> {t.approve}</button><button onClick={() => deleteTask(task.id)} className="px-4 py-2.5 rounded-lg hover:bg-red-50" style={{ color: '#ea4335', border: '1px solid #f5c6cb' }}><X size={18} /></button></div></div>; })}</div>; }

// === TASK ITEM — ZMIANA #1: strzałki zawsze widoczne + ZMIANA #3: custom tagi ===
function TaskItem({ task, isSelected, onClick, onStatusChange, onMoveUp, onMoveDown, showMoveButtons, currentUser, readTimestamps, seenTaskIds, lang, t, teamMembers, customTags }) {
  const mk = MARKETS.find(m => m.id === task.market); const st = STATUSES.find(s => s.id === task.status); const Icon = st?.icon || Circle;
  const cycle = (e) => { e.stopPropagation(); onStatusChange(task.status === 'open' ? 'closed' : 'open'); };
  const uc = getUnreadCount(task, currentUser, readTimestamps); const mc = getMentionsForUser(task, currentUser, readTimestamps, teamMembers).length;
  const isNew = task.assignees?.includes(currentUser) && task.createdBy !== currentUser && !seenTaskIds.includes(task.id);
  const hasEP = task.isExternal && task.submitterEmail && task.status === 'closed' && !(task.emailHistory || []).some(e => e.type === 'completed' && e.success);
  const tTags = (task.tags || []).map(tid => (customTags || []).find(ct => ct.id === tid)).filter(Boolean);
  return <div onClick={onClick} className="bg-white rounded-lg px-3 py-2.5 cursor-pointer hover:shadow-sm border" style={{ borderColor: isSelected ? '#1a73e8' : isNew ? '#c6dafc' : '#e8eaed', background: isNew ? '#f8fbff' : 'white' }}><div className="flex items-center gap-2">
    {showMoveButtons && <div className="flex flex-col gap-0.5 flex-shrink-0"><button onClick={e => { e.stopPropagation(); onMoveUp?.(); }} className="p-0.5 rounded hover:bg-gray-100" style={{ color: '#bdc1c6' }} title={t.moveUp}><ChevronUp size={14} /></button><button onClick={e => { e.stopPropagation(); onMoveDown?.(); }} className="p-0.5 rounded hover:bg-gray-100" style={{ color: '#bdc1c6' }} title={t.moveDown}><ChevronDown size={14} /></button></div>}
    <button onClick={cycle} className="hover:scale-110 flex-shrink-0"><Icon size={18} style={{ color: st?.color }} className={task.status === 'closed' ? 'fill-current' : ''} /></button>
    <span className="flex-shrink-0">{mk?.icon}</span>
    <h4 className="font-medium text-sm flex-1 min-w-0 truncate" style={{ color: task.status === 'closed' ? '#9aa0a6' : '#202124', textDecoration: task.status === 'closed' ? 'line-through' : 'none' }}>{task.title}</h4>
    <div className="flex items-center gap-1.5 flex-shrink-0 flex-wrap justify-end">
      <PriorityBadge priority={task.priority} size="small" lang={lang} />
      {tTags.map(tg => <span key={tg.id} className="text-xs px-1.5 py-0.5 rounded-full font-medium" style={{ background: tg.color + '20', color: tg.color }}>{tg.name}</span>)}
      {isNew && <span className="flex items-center gap-1 px-1.5 py-0.5 rounded-full text-xs font-medium" style={{ background: '#1a73e8', color: 'white' }}><Sparkles size={10} />{t.new}</span>}
      {mc > 0 && <span className="flex items-center gap-1 px-1.5 py-0.5 rounded-full text-xs font-medium" style={{ background: '#ea4335', color: 'white' }}><AtSign size={10} />{mc}</span>}
      {uc > 0 && mc === 0 && <span className="flex items-center gap-1 px-1.5 py-0.5 rounded-full text-xs font-medium" style={{ background: '#fbbc04', color: 'white' }}><MessageSquare size={10} />{uc}</span>}
      {hasEP && <MailX size={10} style={{ color: '#ea4335' }} />}
      {task.isExternal && <ExternalLink size={12} style={{ color: '#fbbc04' }} />}
      {task.language === 'en' && <TranslateButton task={task} size="small" />}
      {task.status === 'ideas' && <span className="text-xs hidden sm:inline">💡</span>}
      {task.market === 'pl' && task.subcategory && (() => { const sc = PL_SUBCATEGORIES.find(s => s.id === task.subcategory); return sc && <span className="text-xs px-1.5 py-0.5 rounded-full font-medium hidden sm:inline" style={{ background: sc.bg, color: sc.color }}>{sc.name}</span>; })()}
      <div className="flex -space-x-1">{task.assignees?.slice(0, 3).map(aId => { const m = teamMembers.find(x => x.id === aId); return m && <div key={aId} className="w-5 h-5 rounded-full flex items-center justify-center text-white text-xs font-medium border border-white" style={{ background: m.color }} title={m.name}>{getInitials(m.name)}</div>; })}{task.assignees?.length > 3 && <div className="w-5 h-5 rounded-full flex items-center justify-center text-xs font-medium border border-white" style={{ background: '#e8eaed', color: '#5f6368' }}>+{task.assignees.length - 3}</div>}</div>
      {task.comments?.length > 0 && !uc && <div className="flex items-center gap-0.5 hidden sm:flex" style={{ color: '#9aa0a6' }}><MessageSquare size={12} /><span className="text-xs">{task.comments.length}</span></div>}
      <SubtaskProgress subtasks={task.subtasks} />
      <ChevronRight size={16} style={{ color: '#dadce0' }} />
    </div>
  </div></div>;
}
// === TASK DETAIL — ZMIANA #2: kompaktowy sidebar + ZMIANA #3: custom tagi ===
function TaskDetail({ task, updateTask, deleteTask, onClose, currentUser, isManager, onMarkUnread, readTimestamps, t, lang, teamMembers, customTags, onRefreshTags }) {
  const [comment, setComment] = useState(''); const [editing, setEditing] = useState(false); const [form, setForm] = useState({ title: '', description: '' }); const [newSubtask, setNewSubtask] = useState(''); const [subtaskAssignee, setSubtaskAssignee] = useState(''); const [showSubtaskForm, setShowSubtaskForm] = useState(false); const [linkCopied, setLinkCopied] = useState(false); const [uploading, setUploading] = useState(false); const [commentAttachments, setCommentAttachments] = useState([]); const [uploadingComment, setUploadingComment] = useState(false); const [editingCommentId, setEditingCommentId] = useState(null); const [editingCommentText, setEditingCommentText] = useState(''); const [showTagManager, setShowTagManager] = useState(false); const [newTagName, setNewTagName] = useState(''); const [newTagColor, setNewTagColor] = useState(TAG_COLORS[0]);

  useEffect(() => { setForm({ title: task.title, description: task.description || '' }); setEditing(false); setComment(''); setNewSubtask(''); setSubtaskAssignee(''); setShowSubtaskForm(false); setLinkCopied(false); setCommentAttachments([]); setEditingCommentId(null); setShowTagManager(false); }, [task.id]);
  
  const market = MARKETS.find(m => m.id === task.market); const me = teamMembers.find(m => m.id === currentUser); const subtasks = task.subtasks || []; const canEdit = isManager || task.createdBy === currentUser; const canContribute = canEdit || task.assignees?.includes(currentUser);
  const publicLink = task.publicToken ? `${typeof window !== 'undefined' ? window.location.origin : ''}/task/${task.publicToken}` : null;
  const copyPublicLink = () => { if (publicLink) { navigator.clipboard.writeText(publicLink); setLinkCopied(true); setTimeout(() => setLinkCopied(false), 2000); } };
  const handleTaskAttachmentUpload = async (files) => { setUploading(true); const up = []; for (const file of files) { const r = await uploadFile(file, `tasks/${task.id}`); if (r) { r.uploadedBy = currentUser; up.push(r); } } if (up.length > 0) await updateTask(task.id, { attachments: [...(task.attachments || []), ...up] }); setUploading(false); };
  const handleRemoveTaskAttachment = async (aid) => { await updateTask(task.id, { attachments: (task.attachments || []).filter(a => a.id !== aid) }); };
  const handleCommentAttachmentUpload = async (files) => { setUploadingComment(true); for (const file of files) { const r = await uploadFile(file, `comments/${task.id}`); if (r) { r.uploadedBy = currentUser; setCommentAttachments(prev => [...prev, r]); } } setUploadingComment(false); };
  const addComment = async () => { if (!comment.trim() && commentAttachments.length === 0) return; const nc = { id: generateId(), text: comment.trim(), author: currentUser, createdAt: new Date().toISOString(), attachments: commentAttachments.length > 0 ? commentAttachments : undefined, mentions: parseMentions(comment.trim()), reactions: [] }; updateTask(task.id, { comments: [...(task.comments || []), nc] }); setComment(''); setCommentAttachments([]); };
  const toggleReaction = (cid) => { const uc = (task.comments || []).map(c => { if (c.id !== cid) return c; const rx = c.reactions || []; return { ...c, reactions: rx.includes(currentUser) ? rx.filter(r => r !== currentUser) : [...rx, currentUser] }; }); updateTask(task.id, { comments: uc }); };
  const startEditComment = (c) => { setEditingCommentId(c.id); setEditingCommentText(c.text); };
  const saveEditComment = () => { if (!editingCommentText.trim()) return; updateTask(task.id, { comments: (task.comments || []).map(c => c.id !== editingCommentId ? c : { ...c, text: editingCommentText.trim(), editedAt: new Date().toISOString() }) }); setEditingCommentId(null); setEditingCommentText(''); };
  const cancelEditComment = () => { setEditingCommentId(null); setEditingCommentText(''); };
  const save = () => { updateTask(task.id, { title: form.title, description: form.description }); setEditing(false); };
  const addSubtask = () => { if (!newSubtask.trim()) return; updateTask(task.id, { subtasks: [...subtasks, { id: generateId(), title: newSubtask.trim(), assignee: subtaskAssignee || null, status: 'open', createdAt: new Date().toISOString() }] }); setNewSubtask(''); setSubtaskAssignee(''); setShowSubtaskForm(false); };
  const toggleSubtask = (sid) => { updateTask(task.id, { subtasks: subtasks.map(s => s.id === sid ? { ...s, status: s.status === 'open' ? 'closed' : 'open' } : s) }); };
  const deleteSubtask = (sid) => { updateTask(task.id, { subtasks: subtasks.filter(s => s.id !== sid) }); };
  const updateSubtaskAssignee = (sid, aid) => { updateTask(task.id, { subtasks: subtasks.map(s => s.id === sid ? { ...s, assignee: aid || null } : s) }); };
  const toggleTag = (tagId) => { const cur = task.tags || []; updateTask(task.id, { tags: cur.includes(tagId) ? cur.filter(id => id !== tagId) : [...cur, tagId] }); };
  const handleCreateTag = async () => { if (!newTagName.trim()) return; await createCustomTag({ name: newTagName.trim(), color: newTagColor, createdBy: currentUser }); setNewTagName(''); setNewTagColor(TAG_COLORS[0]); if (onRefreshTags) onRefreshTags(); };
  const handleDeleteTag = async (tagId) => { await deleteCustomTagDb(tagId); const cur = task.tags || []; if (cur.includes(tagId)) updateTask(task.id, { tags: cur.filter(id => id !== tagId) }); if (onRefreshTags) onRefreshTags(); };
  const fd = lang === 'en' ? formatDateTimeEn : formatDateTime;

  return (
    <aside className="w-full lg:w-[640px] bg-white border-l flex flex-col overflow-hidden flex-shrink-0 fixed lg:static inset-0 z-40 lg:z-auto" style={{ borderColor: '#e8eaed' }}>
      <div className="p-3 border-b flex items-center justify-between" style={{ borderColor: '#e8eaed' }}>
        <div className="flex items-center gap-2"><span className="text-lg">{market?.icon}</span><span className="text-sm font-medium" style={{ color: '#202124' }}>{lang === 'en' ? market?.nameEn : market?.name}</span>{task.isExternal && <ExternalLink size={14} style={{ color: '#fbbc04' }} />}{task.language === 'en' && <span className="text-xs px-1.5 py-0.5 rounded" style={{ background: '#e8f0fe', color: '#1a73e8' }}>🇬🇧</span>}</div>
        <div className="flex items-center gap-1">{task.language === 'en' && <TranslateButton task={task} />}{publicLink && <button onClick={copyPublicLink} className="p-1.5 rounded-full hover:bg-blue-50" style={{ color: linkCopied ? '#34a853' : '#1a73e8' }}>{linkCopied ? <Check size={16} /> : <Link2 size={16} />}</button>}{canEdit && <><button onClick={() => setEditing(!editing)} className="p-1.5 rounded-full hover:bg-gray-100" style={{ color: '#5f6368' }}><Edit3 size={16} /></button><button onClick={() => deleteTask(task.id)} className="p-1.5 rounded-full hover:bg-red-50" style={{ color: '#5f6368' }}><Trash2 size={16} /></button></>}<button onClick={onClose} className="p-1.5 rounded-full hover:bg-gray-100" style={{ color: '#5f6368' }}><X size={16} /></button></div>
      </div>
      {publicLink && <div className="px-3 py-1.5 border-b flex items-center gap-2" style={{ background: '#e8f0fe', borderColor: '#c6dafc' }}><Link2 size={12} style={{ color: '#1a73e8' }} /><code className="flex-1 text-xs truncate" style={{ color: '#1a73e8' }}>{publicLink}</code><button onClick={copyPublicLink} className="text-xs px-2 py-0.5 rounded hover:bg-blue-100" style={{ color: '#1a73e8' }}>{linkCopied ? '✓' : t.copyLink}</button></div>}
      
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {task.isExternal && <div className="p-2 rounded-lg text-sm" style={{ background: '#fef7e0', border: '1px solid #feefc3', color: '#b06000' }}>📨 {t.from}: <strong>{task.submittedBy}</strong> {task.submitterEmail && `(${task.submitterEmail})`}</div>}
        
        {editing ? <div className="space-y-3"><input type="text" value={form.title} onChange={e => setForm({...form, title: e.target.value})} className="w-full px-3 py-2 border rounded-lg text-lg font-medium" style={{ borderColor: '#dadce0', color: '#202124' }} /><RichTextEditor value={form.description} onChange={v => setForm({...form, description: v})} placeholder={t.taskDetails} minHeight="150px" /><div className="flex gap-2"><button onClick={save} className="flex-1 py-2 rounded-lg font-medium text-sm" style={{ background: '#1a73e8', color: 'white' }}>{t.save}</button><button onClick={() => setEditing(false)} className="flex-1 py-2 rounded-lg text-sm" style={{ background: '#f1f3f4', color: '#5f6368' }}>{t.cancel}</button></div></div> : <div><div className="flex items-center gap-2 flex-wrap mb-2"><h3 className="font-medium text-lg" style={{ color: '#202124' }}>{task.title}</h3><PriorityBadge priority={task.priority} lang={lang} /></div><RichTextDisplay html={task.description} /></div>}

        {/* ZMIANA #2: Kompaktowy wiersz kontrolek */}
        <div className="flex flex-wrap gap-2 items-center p-3 rounded-lg" style={{ background: '#f8f9fa', border: '1px solid #e8eaed' }}>
          <select value={task.market} onChange={e => updateTask(task.id, { market: e.target.value, subcategory: e.target.value === 'pl' ? task.subcategory : null })} className="text-xs px-2 py-1.5 border rounded-lg font-medium" style={{ borderColor: '#dadce0', color: '#5f6368' }}>
            {MARKETS.map(m => <option key={m.id} value={m.id}>{m.icon} {lang === 'en' ? m.nameEn : m.name}</option>)}
          </select>
          <select value={task.status} onChange={e => updateTask(task.id, { status: e.target.value })} className="text-xs px-2 py-1.5 border rounded-lg font-medium" style={{ borderColor: '#dadce0', color: STATUSES.find(s => s.id === task.status)?.color, background: STATUSES.find(s => s.id === task.status)?.bg }}>
            {STATUSES.filter(s => s.id !== 'pending').map(s => <option key={s.id} value={s.id}>{lang === 'en' ? s.nameEn : s.name}</option>)}
          </select>
          <select value={task.priority || ''} onChange={e => updateTask(task.id, { priority: e.target.value || null })} className="text-xs px-2 py-1.5 border rounded-lg" style={{ borderColor: '#dadce0', color: PRIORITIES.find(p => p.id === (task.priority||null))?.color }}>
            {PRIORITIES.map(p => <option key={p.id||'none'} value={p.id||''}>{lang === 'en' ? p.nameEn : p.name}</option>)}
          </select>
          {task.market === 'pl' && <select value={task.subcategory || ''} onChange={e => updateTask(task.id, { subcategory: e.target.value || null })} className="text-xs px-2 py-1.5 border rounded-lg" style={{ borderColor: '#dadce0', color: '#5f6368' }}><option value="">{t.subcategory}: {t.none}</option>{PL_SUBCATEGORIES.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</select>}
          {canContribute && <select onChange={e => { if (e.target.value && !task.assignees?.includes(e.target.value)) { updateTask(task.id, { assignees: [...(task.assignees||[]), e.target.value] }); const m = teamMembers.find(x => x.id === e.target.value); if (m) sendEmailNotification(m.email, m.name, task.title, me?.name); } e.target.value = ''; }} className="text-xs px-2 py-1.5 border rounded-lg cursor-pointer" style={{ borderColor: '#dadce0', color: '#5f6368' }} defaultValue=""><option value="">{t.addPerson}</option>{teamMembers.filter(m => m.isActive !== false && !task.assignees?.includes(m.id)).map(m => <option key={m.id} value={m.id}>{m.name}</option>)}</select>}
        </div>

        {task.assignees?.length > 0 && <div className="flex flex-wrap gap-1.5">{task.assignees.map(aId => { const m = teamMembers.find(x => x.id === aId); return m && <div key={aId} className="flex items-center gap-1.5 rounded-full px-2.5 py-1" style={{ background: '#f1f3f4' }}><div className="w-5 h-5 rounded-full flex items-center justify-center text-white text-xs font-medium" style={{ background: m.color }}>{getInitials(m.name)}</div><span className="text-xs" style={{ color: '#202124' }}>{m.name.split(' ')[0]}</span>{canEdit && <button onClick={() => updateTask(task.id, { assignees: task.assignees.filter(a => a !== aId) })} style={{ color: '#9aa0a6' }}><X size={12} /></button>}</div>; })}</div>}

        {/* ZMIANA #3: Custom Tags */}
        <div>
          <div className="flex items-center justify-between mb-2"><div className="flex items-center gap-2"><Tag size={14} style={{ color: '#5f6368' }} /><label className="text-xs font-medium" style={{ color: '#5f6368' }}>{t.tags}</label></div>{isManager && <button onClick={() => setShowTagManager(!showTagManager)} className="text-xs px-2 py-0.5 rounded hover:bg-gray-100" style={{ color: '#1a73e8' }}>{showTagManager ? t.cancel : t.manageTags}</button>}</div>
          <div className="flex flex-wrap gap-1.5">{(customTags||[]).map(tag => { const isA = (task.tags||[]).includes(tag.id); return <button key={tag.id} onClick={() => toggleTag(tag.id)} className="text-xs px-2.5 py-1 rounded-full font-medium flex items-center gap-1" style={{ background: isA ? tag.color+'25' : '#f1f3f4', color: isA ? tag.color : '#9aa0a6', border: isA ? `1.5px solid ${tag.color}` : '1.5px solid transparent' }}><Tag size={10} />{tag.name}{isA && <Check size={10} />}</button>; })}{(customTags||[]).length === 0 && !showTagManager && <span className="text-xs" style={{ color: '#9aa0a6' }}>{t.noTags}</span>}</div>
          {showTagManager && isManager && <div className="mt-2 p-3 rounded-lg border" style={{ borderColor: '#1a73e8', background: '#f8fbff' }}><div className="flex items-center gap-2 mb-2"><input type="text" value={newTagName} onChange={e => setNewTagName(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleCreateTag()} placeholder={t.tagName} className="flex-1 px-2 py-1.5 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }} /><div className="flex gap-1">{TAG_COLORS.slice(0,6).map(c => <button key={c} type="button" onClick={() => setNewTagColor(c)} className="w-5 h-5 rounded-full" style={{ background: c, border: newTagColor === c ? '2px solid #202124' : '2px solid transparent' }} />)}</div><button onClick={handleCreateTag} className="px-3 py-1.5 rounded-lg text-xs font-medium" style={{ background: '#1a73e8', color: 'white' }}>{t.add}</button></div>{(customTags||[]).length > 0 && <div className="space-y-1 pt-2 border-t" style={{ borderColor: '#e8eaed' }}>{customTags.map(tag => <div key={tag.id} className="flex items-center justify-between py-1"><span className="flex items-center gap-1.5 text-xs"><span className="w-3 h-3 rounded-full" style={{ background: tag.color }} />{tag.name}</span><button onClick={() => handleDeleteTag(tag.id)} className="p-0.5 rounded hover:bg-red-50" style={{ color: '#ea4335' }}><X size={12} /></button></div>)}</div>}</div>}
        </div>

        {task.links && <div><label className="block mb-1 text-xs font-medium" style={{ color: '#5f6368' }}>{t.links}</label><div className="rounded-lg border p-1" style={{ background: '#f8f9fa', borderColor: '#e8eaed' }}><ClickableLinks text={task.links} /></div></div>}
        
        <div><div className="flex items-center justify-between mb-1"><div className="flex items-center gap-2"><Paperclip size={14} style={{ color: '#5f6368' }} /><label className="text-xs font-medium" style={{ color: '#5f6368' }}>{t.attachments} ({task.attachments?.length || 0})</label></div>{canContribute && <AttachmentUploader onUpload={handleTaskAttachmentUpload} uploading={uploading} />}</div><AttachmentList attachments={task.attachments} onRemove={canContribute ? handleRemoveTaskAttachment : undefined} showRemove={canContribute} /></div>
        
        <div><div className="flex items-center justify-between mb-2"><div className="flex items-center gap-2"><ListTodo size={14} style={{ color: '#5f6368' }} /><label className="text-xs font-medium" style={{ color: '#5f6368' }}>{t.subtasks} ({subtasks.filter(s => s.status === 'closed').length}/{subtasks.length})</label></div>{!showSubtaskForm && canContribute && <button onClick={() => setShowSubtaskForm(true)} className="text-xs flex items-center gap-1 px-2 py-0.5 rounded-full hover:bg-gray-100" style={{ color: '#1a73e8' }}><Plus size={14} /> {t.add}</button>}</div><div className="space-y-1">{subtasks.map(sub => { const asgn = teamMembers.find(m => m.id === sub.assignee); const done = sub.status === 'closed'; return <div key={sub.id} className="flex items-center gap-2 px-2 py-1.5 rounded-lg group hover:bg-gray-50"><button onClick={() => toggleSubtask(sub.id)} className="flex-shrink-0">{done ? <CheckSquare size={16} style={{ color: '#34a853' }} /> : <Square size={16} style={{ color: '#dadce0' }} />}</button><span className="flex-1 text-sm" style={{ color: done ? '#9aa0a6' : '#202124', textDecoration: done ? 'line-through' : 'none' }}>{sub.title}</span>{asgn ? <div className="w-5 h-5 rounded-full flex items-center justify-center text-white text-xs font-medium" style={{ background: asgn.color }} title={asgn.name}>{getInitials(asgn.name)}</div> : canContribute && <select onChange={e => updateSubtaskAssignee(sub.id, e.target.value)} className="text-xs px-1 py-0.5 rounded border opacity-0 group-hover:opacity-100" style={{ borderColor: '#dadce0' }} value=""><option value="">+</option>{teamMembers.filter(m => m.isActive !== false).map(m => <option key={m.id} value={m.id}>{m.name.split(' ')[0]}</option>)}</select>}{canContribute && <button onClick={() => deleteSubtask(sub.id)} className="opacity-0 group-hover:opacity-100 p-0.5 hover:bg-red-50 rounded" style={{ color: '#ea4335' }}><X size={14} /></button>}</div>; })}</div>{showSubtaskForm && <div className="mt-2 p-2 rounded-lg border" style={{ borderColor: '#1a73e8', background: '#f8fbff' }}><input type="text" value={newSubtask} onChange={e => setNewSubtask(e.target.value)} onKeyDown={e => e.key === 'Enter' && addSubtask()} placeholder={t.subtaskName} className="w-full px-2 py-1.5 border rounded-lg text-sm mb-2" style={{ borderColor: '#dadce0' }} autoFocus /><div className="flex items-center gap-2"><select value={subtaskAssignee} onChange={e => setSubtaskAssignee(e.target.value)} className="flex-1 px-2 py-1 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }}><option value="">{t.noAssignment}</option>{teamMembers.filter(m => m.isActive !== false).map(m => <option key={m.id} value={m.id}>{m.name}</option>)}</select><button onClick={addSubtask} className="px-3 py-1 rounded-lg text-sm font-medium" style={{ background: '#1a73e8', color: 'white' }}>{t.add}</button><button onClick={() => { setShowSubtaskForm(false); setNewSubtask(''); }} className="px-2 py-1 rounded-lg text-sm" style={{ color: '#5f6368' }}>{t.cancel}</button></div></div>}</div>
        
        {/* Comments */}
        <div>
          <div className="flex items-center justify-between mb-2"><label className="text-xs font-medium" style={{ color: '#5f6368' }}>{t.comments} ({task.comments?.length || 0})</label>{onMarkUnread && getUnreadCount(task, currentUser, readTimestamps) === 0 && task.comments?.length > 0 && <button onClick={() => onMarkUnread(task.id)} className="text-xs px-2 py-0.5 rounded hover:bg-gray-100" style={{ color: '#5f6368' }}>{t.markUnread}</button>}</div>
          <div className="space-y-2 mb-3">{task.comments?.map(c => { const auth = teamMembers.find(m => m.id === c.author); const isExt = c.author === 'external'; const isMy = c.author === currentUser; const rx = c.reactions || []; const myRx = rx.includes(currentUser); const hasMention = c.mentions?.some(m => { const myM = teamMembers.find(tm => tm.id === currentUser); if (!myM) return false; return [currentUser.toLowerCase(), myM.name.split(' ')[0].toLowerCase()].includes(m.toLowerCase()); }); const isEd = editingCommentId === c.id; return <div key={c.id} className="flex gap-2"><div className="w-7 h-7 rounded-full flex items-center justify-center text-white text-xs font-medium flex-shrink-0" style={{ background: isExt ? '#5f6368' : (auth?.color || '#999') }}>{isExt ? '👤' : getInitials(auth?.name || '?')}</div><div className="flex-1 min-w-0"><div className="rounded-lg p-2" style={{ background: hasMention ? '#fce8e6' : '#f1f3f4' }}><div className="flex items-center gap-2 mb-0.5"><span className="text-xs font-medium" style={{ color: '#202124' }}>{isExt ? (c.authorName || task.submittedBy || 'Zewnętrzny') : (auth?.name || t.unknown)}</span><span className="text-xs" style={{ color: '#9aa0a6' }}>{fd(c.createdAt)}</span>{c.editedAt && <span className="text-xs italic" style={{ color: '#9aa0a6' }}>({t.edited})</span>}</div>{isEd ? <div className="space-y-1"><input type="text" value={editingCommentText} onChange={e => setEditingCommentText(e.target.value)} onKeyDown={e => { if (e.key === 'Enter') saveEditComment(); if (e.key === 'Escape') cancelEditComment(); }} className="w-full px-2 py-1 border rounded text-sm" style={{ borderColor: '#1a73e8' }} autoFocus /><div className="flex gap-1"><button onClick={saveEditComment} className="text-xs px-2 py-0.5 rounded font-medium" style={{ background: '#1a73e8', color: 'white' }}>{t.saveComment}</button><button onClick={cancelEditComment} className="text-xs px-2 py-0.5 rounded" style={{ color: '#5f6368' }}>{t.cancelEdit}</button></div></div> : <p className="text-sm" style={{ color: '#3c4043' }}><CommentText text={c.text} teamMembers={teamMembers} /></p>}<AttachmentList attachments={c.attachments} showRemove={false} /></div><div className="flex items-center gap-2 mt-0.5 ml-1"><button onClick={() => toggleReaction(c.id)} className={`flex items-center gap-1 px-1.5 py-0.5 rounded-full text-xs ${myRx ? 'bg-blue-50' : 'hover:bg-gray-100'}`} style={{ color: myRx ? '#1a73e8' : '#9aa0a6' }}><ThumbsUp size={10} className={myRx ? 'fill-current' : ''} />{rx.length > 0 && <span>{rx.length}</span>}</button>{isMy && !isEd && <button onClick={() => startEditComment(c)} className="text-xs px-1.5 py-0.5 rounded-full hover:bg-gray-100" style={{ color: '#9aa0a6' }}>{t.editComment}</button>}</div></div></div>; })}</div>
          <div className="flex gap-2 items-start"><MentionInput value={comment} onChange={setComment} onSubmit={addComment} placeholder={t.writeComment} teamMembers={teamMembers} /><AttachmentUploader onUpload={handleCommentAttachmentUpload} uploading={uploadingComment} /><button onClick={addComment} className="p-2 rounded-xl" style={{ background: '#1a73e8', color: 'white' }}><Send size={16} /></button></div>
          <AttachmentList attachments={commentAttachments} onRemove={(id) => setCommentAttachments(p => p.filter(a => a.id !== id))} />
        </div>
        
        <div className="pt-3 border-t text-xs" style={{ borderColor: '#e8eaed', color: '#9aa0a6' }}><p>{t.created}: {fd(task.createdAt)}</p>{task.createdBy && <p>{t.byPerson}: {teamMembers.find(m => m.id === task.createdBy)?.name}</p>}</div>
      </div>
    </aside>
  );
}

// === NEW TASK MODAL (dodano ideas do type selector) ===
function NewTaskModal({ onClose, onSave, currentUser, restrictedMarket, t, lang, teamMembers }) {
  const [f, sF] = useState({ title: '', description: '', market: restrictedMarket || 'pl', status: 'open', assignees: [currentUser], priority: null, subcategory: null, attachments: [] });
  const [uploading, setUploading] = useState(false);
  const tog = (id) => sF(p => ({...p, assignees: p.assignees.includes(id) ? p.assignees.filter(a => a !== id) : [...p.assignees, id]}));
  const sv = () => { if (f.title.trim()) onSave(f); };
  const hUp = async (files) => { setUploading(true); for (const file of files) { const r = await uploadFile(file, 'tasks/new'); if (r) { r.uploadedBy = currentUser; sF(p => ({...p, attachments: [...p.attachments, r]})); } } setUploading(false); };
  return <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4" onClick={onClose}><div className="bg-white rounded-xl w-full max-w-lg max-h-[90vh] overflow-y-auto" style={{ boxShadow: '0 24px 38px 3px rgba(0,0,0,.14)' }} onClick={e => e.stopPropagation()}><div className="p-5 border-b flex items-center justify-between" style={{ borderColor: '#e8eaed' }}><h3 className="text-lg font-medium" style={{ color: '#202124' }}>{t.newTask}</h3><button onClick={onClose} style={{ color: '#5f6368' }}><X size={20} /></button></div><div className="p-5 space-y-4"><div><label className="text-sm font-medium block mb-1.5" style={{ color: '#202124' }}>{t.title} *</label><input type="text" value={f.title} onChange={e => sF({...f, title: e.target.value})} className="w-full px-4 py-2.5 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }} placeholder={t.whatToDo} autoFocus /></div><div><label className="text-sm font-medium block mb-1.5" style={{ color: '#202124' }}>{t.description}</label><RichTextEditor value={f.description} onChange={v => sF({...f, description: v})} placeholder={t.taskDetails} minHeight="120px" /></div><div><div className="flex items-center justify-between mb-1.5"><label className="text-sm font-medium" style={{ color: '#202124' }}>{t.attachments}</label><AttachmentUploader onUpload={hUp} uploading={uploading} /></div><AttachmentList attachments={f.attachments} onRemove={id => sF(p => ({...p, attachments: p.attachments.filter(a => a.id !== id)}))} /></div><div><label className="text-sm font-medium block mb-1.5" style={{ color: '#202124' }}>{t.priority}</label><div className="flex flex-wrap gap-2">{PRIORITIES.map(p => <button key={p.id||'none'} type="button" onClick={() => sF({...f, priority: p.id})} className="flex items-center gap-1 px-3 py-1.5 rounded-full text-sm" style={{ background: f.priority === p.id ? p.bg : '#f1f3f4', color: f.priority === p.id ? p.color : '#5f6368', border: f.priority === p.id ? `2px solid ${p.color}` : '2px solid transparent' }}>{p.id && <Flag size={12} />}{lang === 'en' ? p.nameEn : p.name}</button>)}</div></div><div className="grid grid-cols-2 gap-4"><div><label className="text-sm font-medium block mb-1.5" style={{ color: '#202124' }}>{t.market}</label><select value={f.market} onChange={e => sF({...f, market: e.target.value, subcategory: e.target.value === 'pl' ? f.subcategory : null})} className="w-full px-4 py-2.5 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }} disabled={!!restrictedMarket}>{MARKETS.map(m => <option key={m.id} value={m.id}>{m.icon} {lang === 'en' ? m.nameEn : m.name}</option>)}</select></div><div><label className="text-sm font-medium block mb-1.5" style={{ color: '#202124' }}>{t.type}</label><select value={f.status} onChange={e => sF({...f, status: e.target.value})} className="w-full px-4 py-2.5 border rounded-lg text-sm" style={{ borderColor: '#dadce0' }}><option value="open">{t.open}</option><option value="longterm">{t.longterm}</option><option value="paused">{t.paused}</option><option value="monitoring">{t.monitoring}</option><option value="ideas">{t.ideas}</option></select></div></div>{f.market === 'pl' && <div><label className="text-sm font-medium block mb-1.5" style={{ color: '#202124' }}>{t.subcategory}</label><div className="flex gap-2"><button type="button" onClick={() => sF({...f, subcategory: null})} className="px-3 py-1.5 rounded-full text-sm" style={{ background: !f.subcategory ? '#f1f3f4' : 'white', color: '#5f6368', border: !f.subcategory ? '2px solid #5f6368' : '2px solid #dadce0' }}>{t.none}</button>{PL_SUBCATEGORIES.map(s => <button key={s.id} type="button" onClick={() => sF({...f, subcategory: s.id})} className="px-3 py-1.5 rounded-full text-sm" style={{ background: f.subcategory === s.id ? s.bg : 'white', color: f.subcategory === s.id ? s.color : '#5f6368', border: f.subcategory === s.id ? `2px solid ${s.color}` : '2px solid #dadce0' }}>{s.name}</button>)}</div></div>}<div><label className="text-sm font-medium block mb-2" style={{ color: '#202124' }}>{t.assignToPerson}</label><div className="flex flex-wrap gap-2">{teamMembers.filter(m => m.isActive !== false).map(m => <button key={m.id} type="button" onClick={() => tog(m.id)} className="flex items-center gap-2 px-3 py-2 rounded-full border text-sm" style={{ borderColor: f.assignees.includes(m.id) ? '#1a73e8' : '#dadce0', background: f.assignees.includes(m.id) ? '#e8f0fe' : 'white', color: f.assignees.includes(m.id) ? '#1a73e8' : '#202124' }}><div className="w-5 h-5 rounded-full flex items-center justify-center text-white text-xs font-medium" style={{ background: m.color }}>{getInitials(m.name)}</div><span>{m.name.split(' ')[0]}</span>{f.assignees.includes(m.id) && <Check size={14} />}</button>)}</div></div></div><div className="p-5 border-t flex justify-end gap-3" style={{ borderColor: '#e8eaed' }}><button onClick={onClose} className="px-5 py-2.5 rounded-lg text-sm font-medium hover:bg-gray-100" style={{ color: '#5f6368' }}>{t.cancel}</button><button onClick={sv} className="px-5 py-2.5 rounded-lg text-sm font-medium" style={{ background: '#1a73e8', color: 'white' }}>{t.createTask}</button></div></div></div>;
}

// === MAIN APP ===
export default function TaskApp() {
  const [currentUser, setCurrentUser] = useState(null); const [teamMembers, setTeamMembers] = useState(FALLBACK_TEAM); const [tasks, setTasks] = useState([]); const [loading, setLoading] = useState(true); const [loadingTeam, setLoadingTeam] = useState(true); const [selectedTask, setSelectedTask] = useState(null); const [showNewTask, setShowNewTask] = useState(false); const [showUsersPanel, setShowUsersPanel] = useState(false); const [showDashboard, setShowDashboard] = useState(false); const [filterMarket, setFilterMarket] = useState('all'); const [filterPerson, setFilterPerson] = useState('all'); const [filterStatus, setFilterStatus] = useState('active'); const [sortBy, setSortBy] = useState('newest'); const [activeTab, setActiveTab] = useState('tasks'); const [copied, setCopied] = useState(false); const [checkingAuth, setCheckingAuth] = useState(true); const [readTimestamps, setReadTimestamps] = useState({}); const [seenTaskIds, setSeenTaskIds] = useState([]); const [sidebarOpen, setSidebarOpen] = useState(false); const [customTags, setCustomTags] = useState([]); const filtersInitialized = useRef(false);

  useEffect(() => { (async () => { setLoadingTeam(true); const m = await getTeamMembers(); if (m.length > 0) setTeamMembers(m); setLoadingTeam(false); })(); }, []);
  const currentMember = teamMembers.find(m => m.id === currentUser); const lang = currentMember?.language || 'pl'; const t = TRANSLATIONS[lang]; const isManager = currentMember?.isManager || false; const restrictedMarket = currentMember?.restrictedToMarket || null; const seeOnlyAssigned = currentMember?.seeOnlyAssigned || false;
  useEffect(() => { if (currentUser) { setReadTimestamps(getReadTimestamps(currentUser)); setSeenTaskIds(getSeenTaskIds(currentUser)); } }, [currentUser]);
  useEffect(() => { const su = localStorage.getItem('av_tasks_user'); if (su) { (async () => { const m = await getTeamMembers(); if (m.find(x => x.id === su)) { setCurrentUser(su); setTeamMembers(m); } setCheckingAuth(false); })(); } else setCheckingAuth(false); }, []);
  useEffect(() => { if (restrictedMarket) setFilterMarket(restrictedMarket); }, [restrictedMarket]);
  useEffect(() => { if (!currentUser || filtersInitialized.current) return; filtersInitialized.current = true; const sm = localStorage.getItem(`av_filter_market_${currentUser}`); const sp = localStorage.getItem(`av_filter_person_${currentUser}`); if (!restrictedMarket && sm) setFilterMarket(sm); if (sp) setFilterPerson(sp); else if (!isManager) setFilterPerson(currentUser); }, [currentUser, isManager, restrictedMarket]);
  useEffect(() => { if (currentUser && !restrictedMarket) localStorage.setItem(`av_filter_market_${currentUser}`, filterMarket); }, [filterMarket, currentUser, restrictedMarket]);
  useEffect(() => { if (currentUser) localStorage.setItem(`av_filter_person_${currentUser}`, filterPerson); }, [filterPerson, currentUser]);
  const loadTasks = async () => { const d = await getTasks(); setTasks(d); setLoading(false); };
  const loadCustomTags = async () => { setCustomTags(await getCustomTags()); };
  useEffect(() => { if (currentUser) { loadTasks(); loadCustomTags(); } }, [currentUser]);
  useEffect(() => { if (!currentUser) return; const iv = setInterval(loadTasks, 30000); return () => clearInterval(iv); }, [currentUser]);
  const handleLogout = () => { localStorage.removeItem('av_tasks_user'); setCurrentUser(null); setTasks([]); setSelectedTask(null); setShowUsersPanel(false); setShowDashboard(false); filtersInitialized.current = false; };
  const handleSelectTask = useCallback((task) => { setSelectedTask(task); setShowUsersPanel(false); setShowDashboard(false); setSidebarOpen(false); if (currentUser && task) { setTaskRead(task.id, currentUser); setReadTimestamps(prev => ({...prev, [task.id]: new Date().toISOString()})); markTaskAsSeen(task.id, currentUser); setSeenTaskIds(prev => prev.includes(task.id) ? prev : [...prev, task.id]); } }, [currentUser]);
  const handleMarkUnread = useCallback((taskId) => { if (currentUser) { setTaskUnread(taskId, currentUser); setReadTimestamps(prev => { const n = {...prev}; delete n[taskId]; return n; }); } }, [currentUser]);
  const reloadTeamMembers = async () => { const m = await getTeamMembers(); if (m.length > 0) setTeamMembers(m); };

  if (checkingAuth || loadingTeam) return <div className="min-h-screen flex items-center justify-center" style={{ background: '#f8f9fa' }}><Loader2 className="animate-spin" size={32} style={{ color: '#1a73e8' }} /></div>;
  if (!currentUser) return <LoginScreen onLogin={setCurrentUser} teamMembers={teamMembers} />;

  const pendingTasks = tasks.filter(t => t.status === 'pending' && (!restrictedMarket || t.market === restrictedMarket));
  const visibleTasks = tasks.filter(t => { if (t.status === 'pending') return false; if (restrictedMarket && t.market !== restrictedMarket) return false; if (seeOnlyAssigned && !t.assignees?.includes(currentUser)) return false; if (filterMarket !== 'all' && t.market !== filterMarket) return false; if (filterPerson !== 'all' && !t.assignees?.includes(filterPerson)) return false; return true; });
  const getFilteredByStatus = (sf) => { switch(sf) { case 'active': return visibleTasks.filter(t => t.status === 'open' || t.status === 'longterm'); case 'open': return visibleTasks.filter(t => t.status === 'open'); case 'longterm': return visibleTasks.filter(t => t.status === 'longterm'); case 'paused': return visibleTasks.filter(t => t.status === 'paused'); case 'monitoring': return visibleTasks.filter(t => t.status === 'monitoring'); case 'ideas': return visibleTasks.filter(t => t.status === 'ideas'); case 'closed': return visibleTasks.filter(t => t.status === 'closed'); default: return visibleTasks; } };
  const filteredTasks = sortTasks(getFilteredByStatus(filterStatus), sortBy);
  const openTasks = visibleTasks.filter(t => t.status === 'open'); const longtermTasks = visibleTasks.filter(t => t.status === 'longterm'); const pausedTasks = visibleTasks.filter(t => t.status === 'paused'); const monitoringTasks = visibleTasks.filter(t => t.status === 'monitoring'); const ideasTasks = visibleTasks.filter(t => t.status === 'ideas'); const closedTasks = visibleTasks.filter(t => t.status === 'closed');

  const updateTask = async (id, updates, options = {}) => { const old = tasks.find(t => t.id === id); const nt = {...old, ...updates}; setTasks(prev => prev.map(t => t.id === id ? nt : t)); if (selectedTask?.id === id) setSelectedTask(nt); if (updates.status === 'closed' && old?.status !== 'closed' && old?.isExternal && old?.submitterEmail && !options.skipEmail) { const r = await sendCompletedEmail(old, currentMember?.name); const ee = { id: generateId(), type: 'completed', sentAt: new Date().toISOString(), sentBy: currentUser, sentTo: old.submitterEmail, success: r.sent }; updates.emailHistory = [...(old.emailHistory||[]), ee]; nt.emailHistory = updates.emailHistory; setTasks(prev => prev.map(t => t.id === id ? nt : t)); if (selectedTask?.id === id) setSelectedTask(nt); } await updateTaskDb(id, updates); };
  const deleteTask = async (id) => { if (confirm(t.deleteTask)) { setTasks(prev => prev.filter(t => t.id !== id)); setSelectedTask(null); await deleteTaskDb(id); } };
  const approveTask = async (task, assignees) => { await updateTask(task.id, { status: 'open', assignees, approvedAt: new Date().toISOString(), approvedBy: currentUser }); for (const aId of assignees) { const m = teamMembers.find(x => x.id === aId); if (m) await sendEmailNotification(m.email, m.name, task.title, currentMember?.name); } setActiveTab('tasks'); };
  const addTask = async (task) => { const nt = {...task, createdAt: new Date().toISOString(), createdBy: currentUser, isExternal: false, subtasks: []}; const c = await createTask(nt); if (c) await loadTasks(); setShowNewTask(false); for (const aId of task.assignees||[]) { const m = teamMembers.find(x => x.id === aId); if (m && m.id !== currentUser) await sendEmailNotification(m.email, m.name, task.title, currentMember?.name); } };

  // ZMIANA #1: Fix moveTask — atomowy swap z Promise.all
  const moveTask = async (taskId, direction) => {
    const idx = filteredTasks.findIndex(t => t.id === taskId);
    if (idx === -1) return;
    const tgt = direction === 'up' ? idx - 1 : idx + 1;
    if (tgt < 0 || tgt >= filteredTasks.length) return;
    const a = filteredTasks[idx]; const b = filteredTasks[tgt];
    const oA = a.order ?? idx; const oB = b.order ?? tgt;
    setTasks(prev => prev.map(t => { if (t.id === a.id) return {...t, order: oB}; if (t.id === b.id) return {...t, order: oA}; return t; }));
    await Promise.all([updateTaskDb(a.id, { order: oB }), updateTaskDb(b.id, { order: oA })]);
  };

  const formUrl = typeof window !== 'undefined' ? `${window.location.origin}/request` : '/request';
  const copyLink = () => { navigator.clipboard.writeText(formUrl); setCopied(true); setTimeout(() => setCopied(false), 2000); };
  if (loading) return <div className="min-h-screen flex items-center justify-center" style={{ background: '#f8f9fa', color: '#5f6368' }}>{t.loading}</div>;

  return (
    <div className="min-h-screen flex" style={{ background: '#f8f9fa' }}>
      {sidebarOpen && <div className="fixed inset-0 bg-black/50 z-30 lg:hidden" onClick={() => setSidebarOpen(false)} />}
      <aside className={`w-56 flex flex-col min-h-screen flex-shrink-0 border-r bg-white fixed lg:static z-30 transition-transform lg:translate-x-0 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`} style={{ borderColor: '#e8eaed' }}>
        <div className="p-4 border-b flex items-center justify-between" style={{ borderColor: '#e8eaed' }}><div><img src="https://angloville.com/wp-content/themes/angloville/assets/images/logo.svg" alt="Angloville" className="h-7" /><p className="mt-1 text-xs" style={{ color: '#5f6368' }}>{t.marketingTasks}</p></div><button onClick={() => setSidebarOpen(false)} className="p-1 rounded hover:bg-gray-100 lg:hidden" style={{ color: '#5f6368' }}><X size={18} /></button></div>
        <div className="p-3 border-b space-y-2" style={{ borderColor: '#e8eaed' }}>{!restrictedMarket && <select value={filterMarket} onChange={e => setFilterMarket(e.target.value)} className="w-full rounded-lg px-3 py-2 text-sm border" style={{ borderColor: '#dadce0', color: '#202124' }}><option value="all">{t.allMarkets}</option>{MARKETS.map(m => <option key={m.id} value={m.id}>{m.icon} {lang === 'en' ? m.nameEn : m.name}</option>)}</select>}{!seeOnlyAssigned && <select value={filterPerson} onChange={e => setFilterPerson(e.target.value)} className="w-full rounded-lg px-3 py-2 text-sm border" style={{ borderColor: '#dadce0', color: '#202124' }}><option value="all">{t.everyone}</option>{teamMembers.filter(m => m.isActive !== false).map(m => <option key={m.id} value={m.id}>{m.name}</option>)}</select>}</div>
        <div className="p-2 flex-1 overflow-y-auto"><div className="space-y-0.5">
          {isManager && pendingTasks.length > 0 && <button onClick={() => { setActiveTab('pending'); setShowUsersPanel(false); setShowDashboard(false); setSidebarOpen(false); }} className="w-full flex items-center justify-between px-3 py-2 rounded-full text-sm" style={{ background: activeTab === 'pending' ? '#fef7e0' : 'transparent', color: activeTab === 'pending' ? '#b06000' : '#202124' }}><div className="flex items-center gap-3"><AlertCircle size={18} style={{ color: '#fbbc04' }} /><span>{t.pending}</span></div><span className="font-medium" style={{ color: '#fbbc04' }}>{pendingTasks.length}</span></button>}
          {[
            { key: 'active', label: t.active, icon: Filter, color: '#1a73e8', bg: '#e8f0fe', count: openTasks.length + longtermTasks.length, pl: 0 },
            { key: 'open', label: t.open, icon: Circle, color: '#4285f4', bg: '#e8f0fe', count: openTasks.length, pl: 2 },
            { key: 'longterm', label: t.longterm, icon: Clock, color: '#a142f4', bg: '#f3e8fd', count: longtermTasks.length, pl: 2 },
            { key: 'paused', label: t.paused, icon: Pause, color: '#ff7043', bg: '#fff3e0', count: pausedTasks.length, pl: 2 },
            { key: 'monitoring', label: t.monitoring, icon: Eye, color: '#00acc1', bg: '#e0f7fa', count: monitoringTasks.length, pl: 2 },
            { key: 'ideas', label: t.ideas, icon: Lightbulb, color: '#f9ab00', bg: '#fef9e7', count: ideasTasks.length, pl: 2 },
            { key: 'closed', label: t.closed, icon: CheckCircle, color: '#34a853', bg: '#e6f4ea', count: closedTasks.length, pl: 2 },
          ].map(item => { const I = item.icon; const isActive = activeTab === 'tasks' && filterStatus === item.key && !showUsersPanel && !showDashboard; return <button key={item.key} onClick={() => { setActiveTab('tasks'); setFilterStatus(item.key); setShowUsersPanel(false); setShowDashboard(false); setSidebarOpen(false); }} className="w-full flex items-center justify-between px-3 py-2 rounded-full text-sm" style={{ background: isActive ? item.bg : 'transparent', color: isActive ? item.color : '#202124' }}><div className={`flex items-center gap-3 ${item.pl ? 'pl-2' : ''}`}><I size={item.pl ? 16 : 18} style={{ color: item.color }} /><span>{item.label}</span></div><span style={{ color: '#5f6368' }}>{item.count}</span></button>; })}
        </div>
          {isManager && <div className="mt-4 space-y-0.5"><button onClick={() => { setShowDashboard(true); setShowUsersPanel(false); setSelectedTask(null); setSidebarOpen(false); }} className="w-full flex items-center gap-3 px-3 py-2 rounded-full text-sm" style={{ background: showDashboard ? '#e8f0fe' : 'transparent', color: showDashboard ? '#1a73e8' : '#202124' }}><BarChart3 size={18} style={{ color: '#1a73e8' }} /><span>{t.dashboard}</span></button><button onClick={() => { setShowUsersPanel(true); setShowDashboard(false); setSelectedTask(null); setSidebarOpen(false); }} className="w-full flex items-center gap-3 px-3 py-2 rounded-full text-sm" style={{ background: showUsersPanel ? '#e8f0fe' : 'transparent', color: showUsersPanel ? '#1a73e8' : '#202124' }}><Users size={18} style={{ color: '#1a73e8' }} /><span>{t.users}</span></button></div>}
          <div className="mt-4 mx-2 p-3 rounded-lg text-xs hidden lg:block" style={{ background: '#f1f3f4' }}><p className="mb-1.5" style={{ color: '#5f6368' }}>{t.formEn}</p><button onClick={copyLink} className="w-full flex items-center gap-2 px-2 py-1.5 rounded hover:bg-gray-200"><code className="flex-1 text-xs truncate" style={{ color: '#1a73e8' }}>/request</code>{copied ? <Check size={14} style={{ color: '#34a853' }} /> : <Copy size={14} style={{ color: '#5f6368' }} />}</button></div>
          <QuickLinksSection currentUser={currentUser} t={t} />
        </div>
        <div className="p-3 border-t" style={{ borderColor: '#e8eaed' }}><div className="flex items-center gap-2"><div className="w-8 h-8 rounded-full flex items-center justify-center text-white text-xs font-medium" style={{ background: currentMember?.color }}>{getInitials(currentMember?.name || '')}</div><div className="flex-1 min-w-0"><div className="text-sm font-medium truncate" style={{ color: '#202124' }}>{currentMember?.name?.split(' ')[0]}</div>{isManager && <div className="text-xs" style={{ color: '#5f6368' }}>{t.manager}</div>}</div><button onClick={handleLogout} className="p-1.5 rounded-full hover:bg-gray-100" style={{ color: '#5f6368' }}><LogOut size={18} /></button></div></div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden min-w-0">
        <header className="bg-white border-b px-4 lg:px-6 py-3 flex items-center justify-between gap-2" style={{ borderColor: '#e8eaed' }}>
          <div className="flex items-center gap-2 min-w-0"><button onClick={() => setSidebarOpen(true)} className="p-2 rounded-full hover:bg-gray-100 lg:hidden flex-shrink-0" style={{ color: '#5f6368' }}><Menu size={22} /></button><div className="min-w-0"><h2 className="text-base lg:text-lg font-medium truncate" style={{ color: '#202124' }}>{showDashboard ? t.dashboardTitle : showUsersPanel ? t.usersPanel : activeTab === 'pending' ? t.pendingApproval : filterStatus === 'active' ? t.activeTasks : filterStatus === 'open' ? t.openTasks : filterStatus === 'longterm' ? t.longtermTasks : filterStatus === 'paused' ? t.pausedTasks : filterStatus === 'monitoring' ? t.monitoringTasks : filterStatus === 'ideas' ? t.ideasTasks : t.closedTasks}</h2>{filterPerson !== 'all' && !showUsersPanel && !showDashboard && <p className="text-xs" style={{ color: '#5f6368' }}>{t.filter}: {teamMembers.find(m => m.id === filterPerson)?.name}</p>}</div></div>
          <div className="flex items-center gap-2 flex-shrink-0"><NotificationBell tasks={tasks} currentUser={currentUser} readTimestamps={readTimestamps} teamMembers={teamMembers} onSelectTask={handleSelectTask} t={t} lang={lang} />{!showUsersPanel && !showDashboard && activeTab === 'tasks' && <SortDropdown value={sortBy} onChange={setSortBy} t={t} />}{!showUsersPanel && !showDashboard && <><button onClick={loadTasks} className="p-2 rounded-full hover:bg-gray-100" style={{ color: '#5f6368' }}><Loader2 size={18} className={loading ? 'animate-spin' : ''} /></button>{activeTab === 'tasks' && <button onClick={() => setShowNewTask(true)} className="flex items-center gap-2 px-3 lg:px-4 py-2 rounded-lg font-medium text-sm" style={{ background: '#1a73e8', color: 'white' }}><Plus size={18} /> <span className="hidden sm:inline">{t.newTask}</span></button>}</>}</div>
        </header>
        <div className="flex-1 overflow-y-auto p-3 lg:p-4">
          {showDashboard || showUsersPanel ? null : activeTab === 'pending' && isManager ? <PendingView tasks={pendingTasks} approveTask={approveTask} deleteTask={deleteTask} currentUser={currentUser} t={t} lang={lang} teamMembers={teamMembers} /> : (
            <div className="max-w-4xl mx-auto">{filteredTasks.length === 0 ? <div className="text-center py-16"><CheckCircle size={48} className="mx-auto mb-4" style={{ color: '#34a853', opacity: 0.4 }} /><p style={{ color: '#5f6368' }}>{t.noTasksToShow}</p></div> : <div className="space-y-1">{filteredTasks.map(task => <TaskItem key={task.id} task={task} isSelected={selectedTask?.id === task.id} onClick={() => handleSelectTask(task)} onStatusChange={s => updateTask(task.id, { status: s })} onMoveUp={() => moveTask(task.id, 'up')} onMoveDown={() => moveTask(task.id, 'down')} showMoveButtons={sortBy === 'manual'} currentUser={currentUser} readTimestamps={readTimestamps} seenTaskIds={seenTaskIds} lang={lang} t={t} teamMembers={teamMembers} customTags={customTags} />)}</div>}</div>
          )}
        </div>
      </main>
      
      {showDashboard && <DashboardPanel tasks={tasks} teamMembers={teamMembers} onClose={() => setShowDashboard(false)} t={t} lang={lang} />}
      {showUsersPanel && !showDashboard && <UsersPanel teamMembers={teamMembers} onUpdate={reloadTeamMembers} onClose={() => setShowUsersPanel(false)} t={t} />}
      {selectedTask && !showUsersPanel && !showDashboard && <TaskDetail task={selectedTask} updateTask={updateTask} deleteTask={deleteTask} onClose={() => setSelectedTask(null)} currentUser={currentUser} isManager={isManager} onMarkUnread={handleMarkUnread} readTimestamps={readTimestamps} t={t} lang={lang} teamMembers={teamMembers} customTags={customTags} onRefreshTags={loadCustomTags} />}
      {showNewTask && <NewTaskModal onClose={() => setShowNewTask(false)} onSave={addTask} currentUser={currentUser} restrictedMarket={restrictedMarket} t={t} lang={lang} teamMembers={teamMembers} />}
    </div>
  );
}
